const Map<String, (String nameRu, String descRu)> kLandmarkRu = {
  'chengdu/panda': ('База по разведению больших панд', 'Чэндуская научно-исследовательская база разведения большой панды — крупнейший в мире центр охраны и разведения панд. Миллионы гостей приезжают сюда каждый год, чтобы посмотреть, как любимый символ города кувыркается в бамбуковых рощах.'),
  'chengdu/hotpot': ('Сычуаньский хого', 'Хого — кипящий котёл с обжигающим красным маслом и сычуаньским перцем, от которого приятно немеет во рту, — сердце застольной культуры Чэнду. Каждый сам окунает свой кусочек в общий котёл посреди стола: еда здесь превращается в весёлую совместную игру.'),
  'chengdu/bianlian': ('Бяньлянь (Искусство смены масок)', 'Бяньлянь — волшебное искусство сычуаньской оперы: мастера одним движением руки, в мгновение ока, меняют яркие маски на лице. Секрет этого искусства передаётся из поколения в поколение только от мастера к ученику.'),
  'chengdu/jinli': ('Старинная улица Цзиньли', 'Освещённая красными фонарями улица Цзиньли — торговый квартал, чья история восходит к эпохе Трёх царств. Чайные, театр теней и мастера, рисующие драконов расплавленным сахаром, — именно здесь лучше всего чувствуется знаменитый неторопливый ритм жизни Чэнду.'),
  'nanjing/citywall': ('Городская стена Мин', 'Эту исполинскую стену возвёл основатель династии Мин для защиты своей столицы — сегодня это самая длинная сохранившаяся городская стена в мире. На каждом кирпиче в знак качества выбито имя мастера, а прогулка по гребню стены открывает вид сразу на старый и новый Нанкин.'),
  'nanjing/plum': ('Цветы сливы', 'Цветущая сквозь снег посреди зимы слива в китайской культуре символизирует стойкость и надежду — недаром Нанкин выбрал её цветком города. В конце зимы склоны горы Мэйхуа превращаются в розово-белое море лепестков, и горожане выходят гулять под цветущими деревьями.'),
  'nanjing/duck': ('Солёная утка', 'Фирменная нанкинская солёная утка выдерживается в пряном рассоле, бережно отваривается и подаётся холодной. Нежная, деликатная и идеально приправленная утка — настоящая страсть всего города: местные шутят, что ещё ни одна утка не покинула Нанкин живой.'),
  'nanjing/bridge': ('Нанкинский мост через Янцзы', 'Нанкинский мост через Янцзы, достроенный в 1968 году исключительно китайскими инженерами, — огромное двухъярусное сооружение, несущее через реку и автомобильную, и железную дорогу. Построенный без иностранной помощи, он стал гордым символом самостоятельности современного Китая и до сих пор с гордостью упоминается в школьных учебниках.'),
  'qingdao/beer': ('Пиво «Циндао»', 'Пивоварня «Циндао», основанная в германский период истории города, сделала его родиной самого известного пива Китая. Каждое лето город захватывает международный пивной фестиваль, а свежее разливное пиво в полиэтиленовых пакетах, которое пьют через трубочку, остаётся самой милой уличной традицией Циндао.'),
  'qingdao/sailing': ('Город парусов', 'Парусные соревнования Олимпиады 2008 года проходили в марине Циндао, и с тех пор город носит звание «города парусов». С его ветреной бухтой, белыми парусами на горизонте и длинными приморскими променадами это настоящая столица водного спорта Китая.'),
  'qingdao/beach': ('Пляжи', 'Пляжи Циндао расстилаются у подножия холмов с красными крышами зданий германской эпохи, придавая городу редкий для Китая облик европейского приморского городка. Летом песчаные берега заполняют купальщики, а прибрежная дорожка, соединяющая бухту за бухтой, — классический маршрут для прогулки на закате.'),
  'qingdao/crab': ('Морепродукты', 'Обращённый к Жёлтому морю Циндао ест прямо из воды: лотки с моллюсками, устрицами, морскими ежами и крабами теснятся на пирсах. По местному обычаю дневной улов просто готовят на пару и запивают ледяным пивом «Циндао».'),
  'changsha/pepper': ('Перец чили', 'В отличие от «немеющей» остроты Сычуани, хунаньская кухня славится сухим, резким жаром: свежий и маринованный перец чили есть почти в каждом блюде. В Чанше острое — старинный ответ на влажный климат; местные шутят, что боятся не остроты, а её отсутствия.'),
  'changsha/tofu': ('Вонючий тофу', '«Вонючий тофу» из Чанши вымачивают в ферментированном рассоле и обжаривают во фритюре: снаружи он получается угольно-чёрным и хрустящим, внутри — белоснежным и шелковистым. Пусть резкий запах вас не обманет: щедро политый соусом чили, этот маленький деликатес собирает самые длинные очереди на ночных рынках.'),
  'changsha/fireworks': ('Фейерверки', 'Соседний с Чаншей Люян веками считается мировой столицей фейерверков — на родине пороха это ремесло передаётся из поколения в поколение. Во время регулярных шоу на берегах реки Сянцзян небо и вода одновременно вспыхивают всеми красками.'),
  'changsha/orange': ('Остров Цзюцзычжоу', 'Апельсиновый остров — длинная полоска суши посреди реки Сянцзян — получил имя от мандариновых садов на своих берегах. В юности в этих водах плавал Мао Цзэдун, посвятивший острову знаменитое стихотворение; сегодня с его оконечности на реку смотрит гигантский гранитный бюст молодого Мао.'),
  'zhengzhou/kungfu': ('Шаолиньское кунг-фу', 'У подножия горы Суншань недалеко от Чжэнчжоу стоит монастырь Шаолинь — родина чань-буддизма и шаолиньского кунг-фу. Вокруг обители, которой около полутора тысяч лет, тысячи учеников боевых школ поддерживают эту традицию тренировками, начинающимися на рассвете.'),
  'zhengzhou/train': ('Железнодорожный узел', 'Чжэнчжоу вырос в мегаполис на пересечении главных железнодорожных линий Китая — с севера на юг и с востока на запад. Его называют «городом, который построили поезда», и сегодня он остаётся одним из самых загруженных пересадочных узлов высокоскоростной сети страны.'),
  'zhengzhou/wheat': ('Пшеничные равнины', 'Хэнаньская равнина, орошаемая водами Хуанхэ, — одна из главных житниц Китая. Её плодородная земля питает душу северной кухни: тянутая вручную лапша, паровые пельмени и лепёшки с жаровни — всё начинается с зерна этих полей.'),
  'zhengzhou/ding': ('Бронзовый дин', 'В Чжэнчжоу и его окрестностях располагались столицы Шан — одной из древнейших династий Китая, и раскопки здесь открыли ритуальные бронзовые котлы дин. Эти сосуды символизировали власть и подношения предкам — вот почему город причисляют к колыбелям китайской цивилизации.'),
  'wuxi/lake': ('Озеро Тайху', 'Уси стоит на берегу Тайху — одного из крупнейших пресноводных озёр Китая, чья рыба, креветки и водные травы составляют основу местной кухни. Особенно волшебным озеро становится на закате, если смотреть с мыса Юаньтоучжу, — и в пору цветения сакуры.'),
  'wuxi/peach': ('Персик Яншань', 'Городок Яншань под Уси славится на весь Китай персиками — такими сладкими и сочными, что их можно есть ложкой. Плоды созревают в середине лета: в сезон сбора городок охватывает праздничное настроение, а сады открываются для гостей.'),
  'wuxi/figurine': ('Глиняные фигурки Хуэйшань', 'Глиняные фигурки Хуэйшань — многовековое народное ремесло: их лепят из мягкой тёмной глины, добываемой у подножия усийского холма Хуэйшань. Самый любимый персонаж — пухлощёкий малыш А-Фу, символ изобилия и радости; расписанные вручную яркими красками, эти фигурки — классический сувенир города.'),
  'wuxi/boat': ('Лодки на канале', 'Великий канал — самый длинный рукотворный водный путь в мире — протекает через самое сердце Уси. Сесть в лодку в освещённом фонарями квартале у моста Цинмин и скользить мимо старинных домов с белёными стенами и чёрной черепицей — самый красивый способ познакомиться с городом.'),
  'nanning/tree': ('Зелёный город', 'Наньнин, расположенный в тропическом поясе южного Китая, называют «зелёным городом»: его улицы укрывают тенью огромные деревья, а парки остаются пышными круглый год. Близкий к вьетнамской границе, он служит воротами торговли и культурного обмена между Китаем и Юго-Восточной Азией.'),
  'nanning/noodle': ('Лапша «Лаою»', 'Лаою фэнь — «лапша старого друга» — кисло-острая наньнинская классика с маринованными побегами бамбука, ферментированными чёрными бобами и перцем чили. По легенде, хозяин чайной впервые сварил этот суп, чтобы вылечить захворавшего старого друга, — и с тех пор он считается лучшим лекарством от влажных дней.'),
  'nanning/song': ('Чжуанские народные песни', 'Народ чжуан из Гуанси веками выражает чувства в импровизированных песенных перекличках. Каждую весну песенная ярмарка «третьего месяца» наполняет Наньнин состязаниями куплетов, а легендарная певица Лю Саньцзе остаётся самой любимой героиней этой традиции.'),
  'nanning/mango': ('Тропические фрукты', 'Тропический климат делает Наньнин щедрым краем манго, лонгана, личи и папайи: уличные лотки круглый год ломятся от свежих фруктов. Тёплыми вечерами ледяные фруктовые десерты и свежевыжатые соки — любимый способ горожан освежиться.'),
  'nanchang/pavilion': ('Павильон Тэнван', 'Павильон Тэнван на реке Ганьцзян, много раз разрушавшийся и отстраивавшийся заново со времён династии Тан, — одна из трёх самых прославленных башен южного Китая. Предисловие, сочинённое здесь юным поэтом Ван Бо, стало шедевром китайской литературы и обессмертило павильон.'),
  'nanchang/star': ('1 августа', 'Наньчанское восстание 1 августа 1927 года считается днём рождения Народно-освободительной армии Китая, за что Наньчан получил звание «города героев». Иероглифы «8-1» на знамени армии указывают на эту дату — и дали имя центральной площади города.'),
  'nanchang/porcelain': ('Фарфоровый край', 'В провинции Цзянси, столицей которой является Наньчан, находится Цзиндэчжэнь — мировая столица фарфора. Тысячу лет его императорские печи обжигали «белое золото» для дворцов, а караваны и корабли развозили его по всему свету; ремесло живо и сегодня в руках молодых мастеров.'),
  'nanchang/sunset': ('Вид на реку Гань', 'С наступлением вечера оба берега реки Ганьцзян преображаются: фасады сотен зданий превращаются в одно огромное синхронное световое шоу. Прибрежные парки и подсвеченный силуэт павильона Тэнван делают это место любимым маршрутом вечерних прогулок в Наньчане.'),
  'yinchuan/camel': ('Шёлковый путь', 'Иньчуань — оазис, питаемый водами Хуанхэ, — был одними из западных ворот, где караваны Шёлкового пути отдыхали перед выходом в пустыню. За городом до сих пор безмолвно возвышаются под пустынным солнцем похожие на пирамиды царские гробницы династии Западная Ся.'),
  'yinchuan/grapes': ('Виноградники Хэлань', 'Восточные предгорья хребта Хэланьшань с обилием солнца, сухим воздухом и каменистой почвой считаются лучшим винодельческим краем Китая. Вина здешних виноградников завоёвывают международные награды, и ценители уже прозвали регион «китайским Бордо».'),
  'yinchuan/desert': ('Пустыня Шапотоу', 'В Шапотоу близ Иньчуаня золотые дюны пустыни Тэнгэр встречаются с Хуанхэ — это одно из редких мест, где пустыня и река стоят бок о бок. Катание с дюн, караваны верблюдов, уходящие в пески, и переправа через реку на плотах из овечьих шкур — классические приключения этих мест.'),
  'yinchuan/sheep': ('Баранина по-хуэйски', 'Баранина — звезда кухни мусульман-хуэй в Нинся: шашлычки с зирой, нежная отварная баранина и супы с тянутой вручную лапшой заполняют столы города. Местные ягнята, выросшие на степных пастбищах, славятся по всему Китаю нежностью и чистым вкусом мяса.'),
  'lhasa/mountain': ('Дворец Потала', 'Возвышающийся на Красном холме дворец Потала — шедевр тибетской архитектуры с сотнями залов, священными гробницами и часовнями. Бывшая зимняя резиденция далай-лам, это красно-белое здание внесено в список Всемирного наследия ЮНЕСКО и видно почти из любой точки Лхасы.'),
  'lhasa/prayer': ('Храм Джоканг', 'К Джокангу — самому священному храму тибетского буддизма — паломники порой добираются, простираясь ниц на протяжении всего пути. На кольцевом маршруте Баркхор вокруг храма поток верующих, вращающих молитвенные барабаны, не иссякает весь день, а улицы окутывает аромат благовоний.'),
  'lhasa/yak': ('Культура яка', 'Як, созданный для холода высокогорного плато, — опора всей тибетской жизни: его молоко даёт масло и сыр, шерсть идёт на палатки и одежду, а кизяк — на топливо. Даже светильники, горящие в храмах день и ночь, заправляют маслом из молока яка.'),
  'lhasa/tea': ('Чай с ячьим маслом', 'Часуйма — чай, взбитый с ячьим маслом, солью и крепкой тёмной заваркой, — повседневный напиток Тибета. В сухом холоде высокогорья он одновременно согревает и питает, а постоянно подливать чай в чашку гостя — самое милое правило тибетского гостеприимства.'),
  'zhuhai/shell': ('Статуя Девушки-рыбачки', 'Статуя Девы-рыбачки, стоящая на скале в море и поднимающая жемчужину к небу, — эмблема Чжухая. Она родилась из местной легенды о небесной деве, принявшей человеческий облик ради любви к рыбаку, и своей грациозной позой приветствует всех, кто гуляет по прибрежной дороге.'),
  'zhuhai/bridge': ('Мост Гонконг — Чжухай — Макао', 'Мост Гонконг — Чжухай — Макао длиной 55 километров — самый протяжённый морской переход в мире: цепь мостов, искусственных островов и подводного тоннеля. Связав три города дельты Жемчужной реки одной линией, он стал одним из знаковых достижений современной инженерии.'),
  'zhuhai/island': ('Архипелаг Ста Островов', 'Имя Чжухая означает «жемчужное море», а вдоль его побережья рассыпано больше сотни островов. Острова вроде Дунъао и Вайлиндина, куда добираются на пароме, встречают гостей рыбацкими деревушками, тихими бухтами и ресторанами морепродуктов — и каждый живёт в собственном ритме.'),
  'zhuhai/lobster': ('Морские деликатесы', 'Там, где Жемчужная река встречается с морем, Чжухай накрывает стол дневным уловом: лобстеров, раков-богомолов, гребешков и устриц выбирают живыми из аквариумов и готовят на месте. Деликатная кантонская готовка на пару подчёркивает свежесть и природную сладость продукта.'),
  'yantai/apple': ('Яньтайские яблоки', 'Прохладный морской климат и щедрое солнце Яньтая растят самые знаменитые яблоки Китая — красные, хрустящие, с медовым ароматом, их отправляют во все уголки страны. Осенью сады вдоль побережья кипят сбором урожая, и город наполняется яблочным запахом.'),
  'yantai/wine': ('Вино Чанъюй', '«Чанъюй» — первая современная винодельня Китая — была основана в Яньтае в 1892 году и остаётся самым легендарным винным домом страны. С музеем винной культуры, историческими погребами и виноградными маршрутами в окрестностях Яньтай входит в число немногих настоящих «городов вина» Азии.'),
  'yantai/wave': ('Побережье Пэнлай', 'Побережье Пэнлай в Яньтае китайская мифология называет местом, откуда Восемь Бессмертных отправились в путь через море. Миражи, порой мерцающие над водой, принесли этому берегу славу «края небожителей», а исторический павильон Пэнлай смотрит на море со своего утёса.'),
  'yantai/cherry': ('Вишнёвые сады', 'Яньтай — один из главных черешневых краёв Китая: прохладный прибрежный климат идеален для крупных, сочных и сладких ягод. В начале лета сады открываются для гостей, и срывать черешню прямо с ветки — самое сладкое развлечение сезона.'),
  'datong/buddha': ('Гроты Юньган', 'Пещеры Юньган, высеченные в скалах к западу от Датуна, хранят тысячи изваяний Будды эпохи Северная Вэй — это одна из вершин китайского буддийского искусства. Одни фигуры умещаются на ладони, другие высотой с дом; пещеры внесены в список Всемирного наследия ЮНЕСКО.'),
  'datong/citywall': ('Городские стены Датуна', 'Датун, некогда пограничный гарнизонный город, вновь поднял свои стены эпохи Мин — с величественными воротами и угловыми башнями. Прогулка в сумерках по освещённым фонарями укреплениям — лучший способ увидеть в одном кадре крыши старого города и огни нового Датуна.'),
  'datong/noodle': ('Лапша даосяомэнь', 'В даосяомянь — гордости провинции Шаньси — мастер держит на руке брусок теста и ножом состругивает ленты лапши прямо в кипящий котёл. Толстые по краям и тонкие в середине, они идеально держат соус — незаменимая классика датунского стола.'),
  'datong/lantern': ('Висячий монастырь', 'Висячий монастырь, прикреплённый к утёсу горы Хэншань близ Датуна, будто парит в воздухе на тонких деревянных столбах. Постройке около полутора тысяч лет, и она уникальна ещё по одной причине: под одной крышей здесь соседствуют буддизм, даосизм и конфуцианство.'),
  'baotou/horse': ('Степные лошади', 'Название Баотоу по-монгольски означает «место, где водятся олени», а сам город стоит на краю степей Внутренней Монголии. На окрестных пастбищах лошади до сих пор часть повседневной жизни: монгольские скотоводы устраивают скачки, а мелодии моринхура — скрипки с конской головой — звучат в юртах.'),
  'baotou/deer': ('Олений парк', 'Баотоу называют «Городом оленей», и олени, свободно гуляющие по его паркам, оправдывают это имя. Гости могут кормить их с рук — такая трогательная сцена посреди степи открывает удивительно мягкую сторону промышленного города.'),
  'baotou/factory': ('Стальной город', 'В Баотоу работает один из крупнейших производителей стали в Китае, и город занимает особое место на карте тяжёлой промышленности страны. Благодаря близлежащим месторождениям он известен и как один из важнейших мировых центров редкоземельных элементов.'),
  'baotou/grass': ('Поездки по степям', 'Короткая поездка из города приводит в степи, уходящие до самого горизонта. Гостей размещают в юртах и встречают чаем с молоком и жареной бараниной, а вечерами у костра звучат монгольские песни. Степное гостеприимство здесь — традиция многих веков.'),
  'weifang/kite': ('Столица воздушных змеев', 'Вэйфан, который считают родиной воздушного змея, веками хранит это ремесло: бамбуковый каркас и расписанный вручную шёлк. Каждый апрель Вэйфанский международный фестиваль воздушных змеев превращает небо в праздник красок — змеи слетаются сюда со всего мира.'),
  'weifang/woodprint': ('Гравюры Янцзябу', 'Деревня Янцзябу под Вэйфаном — один из самых знаменитых центров красочной ксилографии: такие лубки вешают на двери на китайский Новый год. Боги-хранители дверей, пухлые младенцы и символы изобилия печатаются слой за слоем с вырезанных вручную деревянных досок — ремесло передаётся из поколения в поколение.'),
  'weifang/dragon': ('Воздушные змеи-драконы', 'Звёзды вэйфанского неба — гигантские змеи-«сороконожки» с головой дракона: десятки бамбуковых обручей соединены шёлковым телом, которое волнами тянется по ветру на много метров. Поднять такого великана в воздух — дело, требующее мастерства и силы целой команды.'),
  'weifang/radish': ('Вэйфанская редька', 'Зелёная редька из Вэйфана настолько сладкая и сочная, что местные чистят и режут её, как фрукт. Здешняя поговорка хвастает: «вэйфанская редька лучше груши» — в ней вся гордость за этот скромный овощ; подать гостю редьку к чаю — знак городского радушия.'),
  'dezhou/chicken': ('Дэджоуская курица', 'Пряную тушёную курицу из Дэчжоу готовят до тех пор, пока мясо само не начнёт сходить с костей; её слава разлетелась по стране благодаря оживлённому положению города на Великом канале, а позже — на железной дороге. Глазированная мёдом, обжаренная и медленно томлённая в пряном бульоне, она когда-то подавалась к императорскому столу.'),
  'dezhou/sun': ('Солнечная долина', 'Дэчжоу, рано вложившийся в солнечную энергетику, носит звание «солнечного города»: в его огромном кампусе «Солнечная долина» отели, уличные фонари и дома работают на энергии солнца. Город остаётся одной из самых наглядных витрин возобновляемой энергетики Китая.'),
  'dezhou/grapes': ('Дыни и виноград', 'Плодородные земли равнины Хуанхэ превращают Дэчжоу в край летних плодов: поля полны арбузов, а шпалеры гнутся под гроздьями винограда. Ломоть ледяного арбуза с придорожного лотка — классическая передышка в жаркий летний день.'),
  'dezhou/train': ('Порт на Великом канале', 'В века расцвета Великого канала Дэчжоу был оживлённой пристанью для барж, везущих зерно на север. Сегодня роль канала перешла к железной дороге: стоя на линии Пекин — Шанхай, город остаётся одними из ключевых транспортных ворот северного Китая.'),
  'xuzhou/stone': ('Каменные рельефы династии Хань', 'Сюйчжоу, родина Лю Бана — основателя династии Хань, — это исторический архив, высеченный в камне. Ханьские каменные рельефы, украшавшие погребальные камеры, изображают пиры, колесницы и мифических существ, разворачивая повседневную жизнь двухтысячелетней давности, словно древний комикс.'),
  'xuzhou/terracotta': ('Терракотовая армия', 'Эти терракотовые воины эпохи Хань меньше знаменитой армии из Сианя: их нашли охраняющими гробницу одного из царей Чу. Фигурки высотой по колено выстроены ровными рядами; несмотря на миниатюрный размер, их торжественный строй говорит об армии, призванной служить и после смерти.'),
  'xuzhou/lake': ('Озеро Юньлун', 'Озеро Юньлун, названное в честь «Облачного дракона», — широкое водное зеркало в кольце холмов, зелёные лёгкие города. Сюда, к прибрежным дорожкам, чайным домикам и холмам с храмами, жители Сюйчжоу стекаются в любое время дня — от утренней зарядки до вечерней прогулки.'),
  'xuzhou/skewer': ('Шашлыки', 'Сюйчжоу гордо называет себя шашлычной столицей Китая: дым от бараньих шампуров, вращающихся над углями, до глубокой ночи плывёт по его улицам. Маленькие жаровни ставят прямо на стол, и каждый жарит свой шампур сам — шумный и весёлый ритуал, который делят с друзьями допоздна.'),
  'zhenjiang/vinegar': ('Чжэньцзянский уксус', 'Чёрный рисовый уксус из Чжэньцзяна рождается в долгом, терпеливом брожении клейкого риса; мягкая кислинка и лёгкая сладость сделали его самым знаменитым уксусом китайской кухни. Без него не обходится ни одна трапеза с пельменями — как говорят местные, аромат уксуса витает над улицами Чжэньцзяна.'),
  'zhenjiang/temple': ('Храм Цзиньшань', 'Монастырь Цзиньшань на берегу Янцзы — сцена самого драматичного эпизода «Легенды о Белой змее», любимейшей народной сказки Китая: именно здесь дух змеи Бай Сучжэнь затопила монастырь ради своей любви. Пагода на вершине холма царит над рекой и городом.'),
  'zhenjiang/pot': ('Лапша «Крышка котла»', 'Для чжэньцзянской лапши гогаймянь в большой кипящий котёл опускают маленькую деревянную крышку: плавая на поверхности, она не даёт воде убежать и позволяет лапше свариться идеально. Тонкая лапша встречается с местным уксусом и соевым бульоном — так в этом городе принято начинать день.'),
  'zhenjiang/bridge': ('Берега Янцзы', 'Чжэньцзян — старинный портовый город, основанный в стратегической точке, где Янцзы пересекается с Великим каналом. Три его прибрежных холма — Цзиньшань, Бэйгушань и Цзяошань — с пагодами, храмами и прогулочными парками превращают набережную в зелёную ленту культуры.'),
  'jiaxing/zongzi': ('Цзунцзы', 'Цзясин — столица цзунцзы, свёртков клейкого риса, обёрнутых бамбуковыми листьями и приготовленных на пару. Главное угощение Праздника драконьих лодок продаётся здесь круглый год — со свининой, бобовой пастой или солёным яичным желтком; развернуть горячий цзунцзы — маленькая церемония, которая начинается с аромата листа.'),
  'jiaxing/boat': ('Лодка на Южном озере', 'В 1921 году первый съезд Коммунистической партии Китая, вынужденный покинуть Шанхай, завершился на лодке посреди озера Наньху в Цзясине. Копия «Красной лодки» и сегодня стоит на воде, а туманная гладь, ивы и павильоны на острове придают визиту тихое чувство истории.'),
  'jiaxing/silk': ('Шелковый край', 'Тутовые рощи и культура шелководства Цзяннани веками кормят канальные городки Цзясина. Нить, вытянутая из коконов, превращается здесь в одеяла, ткани и вышивку; мягкость шёлка — дар влажного и мягкого климата региона, протянувшийся от поля до гардероба.'),
  'jiaxing/canal': ('Водный город Учжэнь', 'Учжэнь, входящий в округ Цзясина, — один из самых изящных водных городков Цзяннани с каменными мостами, домами под чёрной черепицей и ступенями, спускающимися прямо к каналу. Когда в сумерках зажигаются фонари, вода вспыхивает красным, а в узких переулках до сих пор живут старинные ремёсла — окраска индиго и театр теней.'),
  'lishui/mountains': ('Зелёные Пики', 'Лишуй — самый гористый уголок провинции Чжэцзян: его долины наполнены туманом, а хребты покрыты бамбуком и соснами. Каменные деревни на склонах и рисовые террасы, касающиеся облаков, хранят медленный, зелёный Китай вдали от суеты прибрежной провинции.'),
  'lishui/camera': ('Рай для Фотографов', 'Долины, залитые предрассветным туманом, крестьяне на террасах и море облаков, меняющееся со светом, сделали Лишуй местом паломничества фотографов. Город известен международными фотособытиями; самые знаменитые кадры ловят миг, когда залитые водой террасы на восходе сверкают золотом.'),
  'lishui/mushroom': ('Грибной Край', 'Уезд Цинъюань в округе Лишуй считается колыбелью грибоводства: способ выращивать шиитаке на брёвнах был придуман в этих горах много веков назад. Деревенские рынки и сегодня пахнут сушёными грибами, а местная кухня гордится супами и тушёными блюдами из свежего урожая.'),
  'lishui/raft': ('Сплав по Реке', 'Река Оуцзян вьётся среди зелёных ущелий Лишуя, и сплав по её прозрачной воде на бамбуковом плоту — классическое удовольствие этих мест. Пока лодочник правит длинным шестом, вдоль берегов проплывают рыбацкие деревни, туманные холмы и пейзажи, будто сошедшие с китайской живописи тушью.'),
  'anqing/opera': ('Хуанмэйская опера', 'Опера хуанмэй выросла из песен сборщиц чая в окрестностях Аньцина и стала одной из самых любимых региональных опер Китая. Её простые, плавные мелодии и истории любви, рассказанные живым народным языком, заучивают наизусть уже много поколений — а Аньцин и сегодня считается столицей этого искусства.'),
  'anqing/pagoda': ('Пагода Чжэньфэн', 'Пагода Чжэньфэн, возвышающаяся на берегу Янцзы, веками служила маяком речным лодочникам и заслужила имя «первой пагоды Янцзы». Восьмигранная башня эпохи Мин награждает тех, кто поднимется по её ярусам, широким видом на великую излучину реки.'),
  'anqing/tea': ('Чай Юэси', 'Туманные прохладные склоны гор Дабешань за Аньцином — идеальный сад для душистого зелёного чая. В уезде Юэси нежные листочки, собранные весной вручную, дают лёгкий цветочный настой, а в горных деревнях сбор чая до сих пор остаётся главным событием сезона.'),
  'anqing/sail': ('Речные Ворота', 'Аньцин, чьё имя означает «мирное торжество», — исторические портовые ворота провинции Аньхой на Янцзы: слог «Ань» в названии самой провинции происходит от этого города. Его набережные и старые кварталы до сих пор хранят следы шумных портовых времён.'),
  'ganzhou/orange': ('Пупочный апельсин Ганьнань', 'Красные почвы Ганьчжоу и мягкий южный климат растят ганьнаньский пупочный апельсин, один из самых сладких в Китае. В сезон урожая холмы окрашиваются в оранжевый; сочный и бессемянный плод разносит имя города по всей стране как предмет гордости.'),
  'ganzhou/house': ('Дома хакка', 'Народ хакка, переселенцы с севера, строил в горных деревнях Ганьчжоу дома-крепости: за их толстыми оборонительными стенами под одной крышей жили десятки семей. Внутри — общие дворы, залы предков и культура крепкой взаимовыручки, сохраняемая веками.'),
  'ganzhou/pavilion': ('Павильон Юйгу', 'Павильон Юйгу смотрит на место, где реки Чжан и Гун сливаются, рождая реку Ганьцзян. Воспетый в стихах поэтов династии Сун, деревянный павильон сплетает речной пейзаж с тысячелетней поэтической традицией; в сумерках это самое задумчивое место города.'),
  'ganzhou/star': ('Великий поход', 'В 1934 году Красная армия начала свой эпический отход, вошедший в историю как Великий поход, из уезда Юйду в округе Ганьчжоу. Историю солдат, всю ночь переправлявшихся через реку, здесь хранят памятники и музеи; город стоит на стартовой черте одного из поворотных моментов новейшей истории Китая.'),
  'putian/shrine': ('Храм Мацзу', 'Богиня Мацзу, покровительница моряков, родилась в Путяне; её главный храм возвышается на острове Мэйчжоу и считается прародителем тысяч храмов Мацзу по всему миру. Вера и обычаи Мацзу внесены в список нематериального наследия ЮНЕСКО, а в праздничные дни остров наполняется дымом благовоний и паломниками.'),
  'putian/lychee': ('Личиновые Рощи', 'Путянь называют ещё «городом личи»: вековые деревья личи до сих пор плодоносят и дарят тень его улицам. Краснеющий к летнему урожаю сладкий плод был южной роскошью, воспетой в классических стихах, а есть личи прямо с ветки — одна из радостей путяньского лета.'),
  'putian/shoe': ('Обувная столица', 'Путянь — один из тихих гигантов мирового производства кроссовок: его мастерские и фабрики выпускают миллионы пар для крупных брендов. Обувное дело здесь похоже на семейное ремесло — от изготовителей колодок до швей целая цепочка мастерства образует невидимую кухню мировой спортивной моды.'),
  'putian/wave': ('Остров Мэйчжоу', 'Остров Мэйчжоу, куда добираются на пароме, славится золотыми пляжами, скалистыми бухтами и храмовыми праздниками Мацзу. В день рождения богини остров оживает под грохот барабанов и шествия; в тихие же дни это обдуваемое морским бризом место паломничества и отдыха у воды.'),
  'mudanjiang/snow': ('Снежный городок Китая', '«Китайский снежный городок» близ Муданьцзяна — одна из самых снежных деревень страны: пышные подушки снега вздымаются на крышах, превращая дома в сказочные избушки. Когда в сумерках зажигаются красные фонари, заснеженные улочки светятся тёплым сиянием.'),
  'mudanjiang/lake': ('Озеро Цзинпо', 'Озеро Цзинпоху, образовавшееся, когда древние вулканические извержения перегородили русло реки, — одно из крупнейших вулканических подпрудных озёр Китая. Его воды низвергаются водопадом Дяошуйлоу, знаменитым летом отважными прыгунами со скал, а зимой — великолепными ледяными пейзажами.'),
  'mudanjiang/tiger': ('Парк сибирских тигров', 'Хэндаохэцзы в окрестностях Муданьцзяна — один из ведущих мировых центров охраны и разведения амурского тигра, самой крупной кошки на планете. Гости наблюдают за тиграми, бродящими по обширным лесным угодьям, с защищённых маршрутов, а сам центр — сердце усилий по спасению будущего этого редкого вида.'),
  'mudanjiang/ski': ('Горнолыжный сезон', 'В Муданьцзяне, в глубине снежного пояса Китая, зимы долгие, а снег выпадает сухой и обильный: лесистые холмы вокруг города каждый сезон заполняются лыжниками. Горнолыжные маршруты в сочетании с поездкой в Снежный городок делают регион одним из центров зимнего туризма северо-восточного Китая.'),
  'changzhou/dino': ('Парк динозавров', 'Чанчжоуский парк динозавров — самый известный в Китае тематический парк, соединяющий музей окаменелостей с настоящим парком развлечений; его ласково называют «китайским Парком юрского периода». С гигантскими фигурами динозавров, водными аттракционами и американскими горками это адрес номер один для семейного отдыха в городе.'),
  'changzhou/pagoda': ('Пагода Тяньнин', '153-метровая пагода храма Тяньнин в центре города считается самой высокой пагодой в мире. Возвышаясь во дворе храма с более чем тысячелетней историей, она с верхнего яруса кладёт к вашим ногам весь Чанчжоу и изгибы Великого канала.'),
  'changzhou/comb': ('Чанчжоуские гребни', 'Чанчжоуский гребень — многовековое ремесло: его вытачивают из ценных пород дерева, самшита и эбена, проходя десятки ручных операций. Когда-то такие гребни подносили императорскому двору; с их тонкой резьбой и расписанными вручную фигурами они и сегодня остаются самым изысканным сувениром города.'),
  'changzhou/canal': ('Великий канал', 'Великий канал веками течёт через Чанчжоу, и город разбогател на торговле и ткачестве, которые принёс этот водный путь. По вечерам старые кварталы вдоль берегов загораются фонарями, а прогулка по каменным набережным — самое классическое из городских удовольствий.'),
  'shaoxing/wine': ('Шаосинское вино', 'Янтарное жёлтое рисовое вино Шаосина сбраживают на воде местного озера Цзяньху; его ценят и как напиток, и как незаменимую приправу китайской кухни. По самой изящной традиции города кувшины с вином закапывали при рождении дочери и открывали на её свадьбе.'),
  'shaoxing/bridge': ('Каменные мосты', 'В пронизанном каналами Шаосине водные пути так же оживлённы, как улицы, а за сотни арочных каменных мостов город называют «музеем мостов». Иные из них стоят веками: их поросшие мхом арки и сегодня дарят тень лодкам, скользящим внизу.'),
  'shaoxing/pen': ('Колыбель каллиграфии', 'Ван Сичжи, почитаемый как величайший мастер каллиграфии, написал свой шедевр — «Предисловие к Павильону орхидей» — на встрече друзей среди бамбуковых рощ Шаосина. С того дня пошёл обычай пускать чарки с вином по ручью, сочиняя стихи, а павильон остаётся священной остановкой для всех влюблённых в кисть.'),
  'shaoxing/boat': ('Лодки упэн', 'В шаосинских лодках упэн с чёрными навесами лодочник гребёт ногами, а руками правит — уникальная техника, передающаяся из поколения в поколение. Скользящие под каменными мостами узких каналов, эти лодки плывут и сквозь детские воспоминания Лу Синя — прославленного писателя, которого вырастил этот город.'),
  'bengbu/shell': ('Жемчужная гавань', 'Имя Бэнбу означает «устричная пристань»: этот участок реки Хуайхэ когда-то славился ловцами пресноводного жемчуга. Жемчужина и сегодня остаётся символом города — она встречается повсюду, от скульптур на площадях до городского герба.'),
  'bengbu/train': ('Железнодорожный узел', 'Бэнбу вырос из маленького городка в крупный город там, где железная дорога Тяньцзинь — Пукоу пересекла реку Хуайхэ. Эти ворота на линии север — юг и сегодня связывают север провинции Аньхой с главной транспортной сетью страны.'),
  'bengbu/river': ('Река Хуайхэ', 'Река Хуайхэ считается природной границей между севером и югом Китая: к северу от неё сеют пшеницу, к югу — рис, а центральное отопление зимой заканчивается у её берегов. Бэнбу живёт прямо на этой переходной линии — между двумя климатами и двумя кухнями.'),
  'bengbu/blossom': ('Весенние ярмарки цветов', 'Весной парки вдоль Хуайхэ покрываются цветами, и жители Бэнбу проводят выходные у реки — с пикниками и цветочными ярмарками. Приозёрный парк Чжангуншань становится самым многолюдным местом встреч города, когда зацветают вишни и персики.'),
  'jiujiang/mountain': ('Гора Лушань', 'Гора Лушань, поднимающаяся между Янцзы и озером Поянху, — самая поэтичная гора Китая: окутанные туманом вершины, водопады и прохладные высокогорья, внесённые в список Всемирного наследия ЮНЕСКО. От строк Ли Бо о её водопаде до каменных вилл горного городка Гулин — здесь каждый уголок рассказывает свою историю.'),
  'jiujiang/tea': ('Чай Юньу', 'Чай юньу («облачный туман»), растущий на укрытых облаками склонах Лушаня, входит в число знаменитых зелёных чаёв Китая. Горная влага и процеженный туманом солнечный свет придают листьям свежий сладковатый аромат; первые весенние побеги собирают вручную и ценят как лучший урожай.'),
  'jiujiang/lake': ('Озеро Поянху', 'Поянху — крупнейшее пресноводное озеро Китая — соединяется с Янцзы прямо у Цзюцзяна. Его воды разливаются и отступают со сменой сезонов, а обнажающиеся зимой влажные луга принимают десятки тысяч перелётных птиц, среди которых и редкий сибирский журавль — стерх.'),
  'jiujiang/scroll': ('Город поэтов', 'Этот старый порт на Янцзы принимал великие имена китайской поэзии: именно здесь Бо Цзюйи написал знаменитую «Песнь о пипе», вдохновлённый мелодией, услышанной на реке. Стоящий в тени горы Лушань Цзюцзян — одни из речных ворот, что чаще всего звучат в стихах.'),
  'quanzhou/ship': ('Морской Шелковый путь', 'Цюаньчжоу, известный средневековому миру как «Зайтон», был крупнейшим портом Морского шёлкового пути — Марко Поло описывал его как одну из самых оживлённых гаваней на земле. Город, где бок о бок стоят мечети, храмы и церкви, за своё космополитичное наследие внесён в список Всемирного наследия ЮНЕСКО.'),
  'quanzhou/mosque': ('Мечеть Цинцзин', 'Мечеть Цинцзин, основанная арабскими купцами в 1009 году, — одна из старейших сохранившихся мечетей Китая. Её гранитный портал и каменные стены, вдохновлённые ближневосточной архитектурой, свидетельствуют о том, каким многоконфессиональным и космополитичным был порт Цюаньчжоу в эпоху Морского шёлкового пути.'),
  'quanzhou/puppet': ('Искусство марионеток', 'В цюаньчжоуском искусстве марионеток мастера оживляют деревянные фигурки, управляя десятками тонких нитей одновременно: куклы могут писать иероглифы или обнажать мечи и сражаться. Эта тысячелетняя традиция остаётся почётным гостем храмовых ярмарок и праздничных сцен.'),
  'quanzhou/tea': ('Чай Тегуаньинь', 'Горный уезд Аньси под Цюаньчжоу — родина Тегуаньинь, «Железной богини», самого знаменитого улуна в мире. Его полуферментированные листья раскрываются с ароматом, напоминающим орхидею, а чайная церемония гунфу-ча с крошечными чашками — здесь просто часть повседневной жизни.'),
  'shanghai/pearl': ('Телебашня «Восточная жемчужина»', 'Башня с розовыми сферами, возвышающаяся в шанхайском районе Луцзяцзуй в Пудуне, — самый узнаваемый силуэт современного Шанхая. Со смотровой площадки со стеклянным полом под ногами расстилаются река Хуанпу и набережная Вайтань на другом берегу, а ночью огни башни переливаются на воде.'),
  'shanghai/bund': ('Набережная Вайтань', 'Исторические фасады банков и отелей вдоль реки Хуанпу хранят величие эпохи, когда Шанхай был мировым портом. На вечерней прогулке по одну сторону светятся старинные торговые дома с каменными колоннами, по другую — небоскрёбы Пудуна: два столетия встречаются в одном взгляде.'),
  'shanghai/garden': ('Сад Юйюань', 'Этот классический сад эпохи Мин с каменными горками, прудами и зигзагообразным мостиком — оазис в самом сердце города. Вокруг шумит базар с чайными и лотками с закусками, а за стенами, увенчанными драконами, скрывается утончённое искусство садов Цзяннани.'),
  'shanghai/xlb': ('Сяолунбао', 'Сяолунбао — пельмешки из тончайшего теста с горячим бульоном внутри — шедевр шанхайской кухни. Сначала надкусывают краешек и выпивают бульон, а затем обмакивают пельмень в чёрный уксус с имбирём. По утрам бамбуковые пароварки окутывают улицы города ароматным паром.'),
  'hangzhou/lake': ('Озеро Сиху', 'Озеро Сиху с ивами, островками и арочными мостами — пейзаж, воспетый в китайской поэзии больше любого другого, и объект Всемирного наследия ЮНЕСКО. Прогулки по дамбам Су и Бай — обычай, которому не одна сотня лет, а Оборванный мост называют местом встречи влюблённых из легенды о Белой змее.'),
  'hangzhou/tea': ('Чай Лунцзин', 'Зелёный чай «Колодец дракона», растущий на склонах вокруг озера, — самый знаменитый чай Китая. Его плоские листья до сих пор формируют вручную, прогревая в горячих котлах, а ранневесенний сбор ценится выше всего. Чашка лунцзина в деревенской чайной — сама душа Ханчжоу.'),
  'hangzhou/temple': ('Храм Линъинь', 'Линъинь, «Храм прибежища души», — один из древнейших буддийских храмов Китая. Напротив него, в скалах пика Фэйлай, за века вырезаны сотни фигур Будды. Прогулка среди дыма благовоний и тени сосен заставляет забыть о шуме города.'),
  'hangzhou/silk': ('Город Шёлка', 'Шёлк в Ханчжоу ткут уже более тысячи лет — город был символом богатства на восточном конце Шёлкового пути. Сегодня на шёлковом рынке торгуют тканями, платками и вышивкой, а музей шёлка рассказывает о пути от кокона до ткацкого станка. Нежный на ощупь ханчжоуский шёлк по-прежнему остаётся самым изысканным подарком.'),
  'chongqing/hongya': ('Хунъядун', 'Хунъядун — комплекс традиционных домов на сваях, прильнувших к скале, — хранит старинную архитектуру горного города. Когда его многоярусные террасы загораются вечерними огнями, он сияет над рекой Цзялин, словно из сказки, а узкие проходы внутри полны местных закусок и ремесленных лавок.'),
  'chongqing/hotpot': ('Чунцинский хого', 'Хого — котелок, бурлящий огненно-красным маслом и сычуаньским перцем, от которого немеет язык, — пламенная душа Чунцина. По легенде, блюдо родилось в котлах грузчиков речных причалов. Каждый кусочек, опущенный в котёл с девятью отделениями посреди стола, превращается в долгий разговор в кругу друзей.'),
  'chongqing/monorail': ('Горный монорельс', 'В холмистом Чунцине линии метро перепрыгивают через долины, а на одной станции поезд и вовсе проходит прямо сквозь жилой дом. Эта сцена стала визитной карточкой города. Со своими склонами, лифтами и мостами «горный город» бросает вызов плоской логике карт.'),
  'chongqing/river': ('Ущелья Янцзы', 'Город возвышается там, где Янцзы встречается с рекой Цзялин, а от причалов Чаотяньмэнь отправляются круизы по Трём ущельям. Пока корабли скользят между отвесными скалами, перед глазами проплывают тысячелетия торговли и поэзии, которые несёт великая река Китая.'),
  'dalian/square': ('Площадь Синхай', 'Выходящая к морю площадь Синхай — одна из крупнейших городских площадей мира; её имя означает «море звёзд». Над её просторными газонами парят воздушные змеи, вечерами вдоль берега скользят велосипедисты, а в дни праздников площадь переполняют концерты и представления.'),
  'dalian/beach': ('Пляжи', 'Со скалистыми бухтами, чистыми пляжами и прохладным летом Далянь — любимый морской курорт севера Китая. Дорога Биньхай, вьющаяся вдоль побережья, открывает захватывающие виды между утёсами и заливами. Когда наступает жара, северяне приезжают сюда дышать морем.'),
  'dalian/football': ('Футбольный город', 'Далянь называют «колыбелью китайского футбола»: отсюда вышли клубы-чемпионы, задававшие тон национальным лигам, и множество игроков сборной. Дети, гоняющие мяч в приморских парках, продолжают традицию, а в дни матчей весь город превращается в единую трибуну.'),
  'dalian/seafood': ('Морепродукты', 'Холодное и чистое Жёлтое море поставляет на столы Даляня гребешки, креветки, морских ежей и трепангов. В прибрежных ресторанах улов выбирают прямо из аквариума и готовят на пару за считанные минуты. А запах жареных кальмаров — душа вечерних рынков.'),
  'shenyang/palace': ('Мукденский дворец', 'Мукденский дворец, построенный основателями династии Цин, был их первой резиденцией до переезда двора в Пекин. Его часто называют младшим братом Запретного города, но восьмиугольные залы в маньчжурском стиле придают ему собственный характер; сегодня это музей из списка ЮНЕСКО.'),
  'shenyang/tomb': ('Гробницы Цин', 'Восточная и Северная гробницы, окружающие город, — монументальные мавзолеи правителей-основателей династии Цин, внесённые в список ЮНЕСКО. Сквозь вековые сосновые леса тянутся священные аллеи с каменными фигурами животных, а осенью парки гробниц одеваются в золото.'),
  'shenyang/factory': ('Промышленная колыбель', 'Значительная часть тяжёлой промышленности Китая родилась в Шэньяне: за огромные машиностроительные заводы город прозвали «Руром Востока». Старые цеха района Тэси сегодня превращаются в музеи и арт-пространства, но гордость поколений, стоявших у станков, всё ещё витает в воздухе.'),
  'shenyang/dumpling': ('Пельмени Лаобянь', 'Паровые пельмени «Лаобянь», которые готовят со времён династии Цин, — фирменное блюдо северного стола. Начинку предварительно обжаривают, чтобы она впитала собственный сок, и это придаёт пельменям несравненную нежность. Корзинка таких пельменей в одном из старинных ресторанов — почти официальное приветствие Шэньяна.'),
  'hefei/judge': ('Храм Бао-гуна', 'Бао Чжэн, легендарный судья династии Сун, родился в Хэфэе; в народе его зовут «Бао Цинтянь» — «чистое небо». Его неподкупная справедливость вдохновила оперы и телесериалы. Мемориальный парк на берегу озера похож на храм, посвящённый честности.'),
  'hefei/science': ('Город науки', 'Хэфэй — город науки, где расположены ведущие университеты и лаборатории Китая. Здесь ведутся проекты от термоядерных экспериментов до квантовых исследований, а кампусы и технопарки придают городу молодой и любознательный дух.'),
  'hefei/lake': ('Озеро Чаоху', 'Чаоху — одно из пяти великих пресноводных озёр Китая, раскинувшееся к югу от Хэфэя. Его серебристая рыбка, белые креветки и крабы известны как «три сокровища». В прибрежных городках рыбацкие лодки и чайные с видом на озеро задают неспешный ритм жизни.'),
  'hefei/cake': ('Кунжутное печенье Лу', 'Старое имя Хэфэя — Лучжоу, и кунжутная лепёшка со сладкой начинкой — старинное лакомство, носящее это имя. Аромат поджаренного кунжута сочетается с мягкой начинкой под хрустящей корочкой. В праздники именно эта лепёшка занимает почётное место в подарочных коробках.'),
  'foshan/wingchun': ('Вин-Чун', 'Боевое искусство вин-чун достигло зрелости в Фошане: здесь учился легендарный мастер Ип Ман, а благодаря его ученику Брюсу Ли это наследие разошлось по всему миру. Мемориальные залы и школы боевых искусств хранят традицию — мастера, отрабатывающие формы в утренних парках, здесь привычное зрелище.'),
  'foshan/lion': ('Танец льва', 'Фошань — столица южного танца льва, и знаменитый народный герой Хуан Фэйхун тоже родом из этих мест. На праздниках яркие львы под бой барабанов прыгают по высоким шестам. Изготовление львиных голов — тонкое ремесло, передаваемое из поколения в поколение.'),
  'foshan/ceramic': ('Керамика Шивань', 'Гончарные печи Шиваня горят, не угасая, уже много веков; печь Наньфэн — одна из старейших действующих дровяных печей Китая. Шиваньская керамика с её выразительными фигурками и глазурованными украшениями венчает даже крыши храмов Гуандуна.'),
  'foshan/opera': ('Кантонская опера', 'Кантонская опера, самое любимое сценическое искусство юга Китая, сложилась на этих землях. Когда-то труппы странствовали по дельте Жемчужной реки на «красных лодках», выступая от деревни к деревне. Пышные костюмы, акробатика и кантонские мелодии и сегодня наполняют театры.'),
  'guiyang/pavilion': ('Павильон Цзясю', 'Трёхъярусный павильон Цзясю, стоящий на скале посреди реки Наньмин, — символ города со времён династии Мин. Его имя означает «первый учёный»: павильон построили с пожеланием, чтобы город растил учёных, блистающих на императорских экзаменах. Когда ночью его огни падают на реку, рождается самый изящный вид Гуйяна.'),
  'guiyang/sourfish': ('Рыба в кислом супе', 'Рыба в кислом супе — фирменное блюдо Гуйчжоу, уходящее корнями в традиции ферментации народа мяо. Пресноводная рыба томится в ярко-красном бульоне, заквашенном на томатах и рисовой закваске. Танец кислого, острого и пряного идеально подходит климату горного юга.'),
  'guiyang/waterfall': ('Водопад Хуангошу', 'Хуангошу, до которого легко добраться из Гуйяна, — один из крупнейших водопадов Азии. За грохочущей стеной воды можно пройти через Пещеру водяного занавеса, а брызги рождают на солнце радуги. В сезон дождей гул водопада разносится по долине на многие километры.'),
  'guiyang/miao': ('Культура Мяо', 'Горные деревни Гуйчжоу — родина народа мяо, славящегося серебряными головными уборами. На праздниках девушки надевают серебряные венцы ручной работы и вышитые наряды, а под мелодию тростниковых труб лушэн собираются хороводы. Батик и вышивка — язык, передаваемый от матерей к дочерям.'),
  'changchun/film': ('Город кино', 'Чанчуньская киностудия — место, где родилось кино нового Китая: здесь снимались классические фильмы страны на протяжении поколений. Потому город и называют «Голливудом Востока». Старые павильоны стали парками на тему кино, а традиция кинофестиваля продолжается.'),
  'changchun/car': ('Автомобильный город', 'Первый китайский грузовик и первый отечественный легковой автомобиль сошли с конвейеров Чанчуня; здесь же выпускают лимузины «Хунци», на которых ездят главы государств. Титул «автомобильной столицы» заслужен сполна: заводы, музеи и автосалоны делают автомобильную культуру самой сутью города.'),
  'changchun/palace': ('Дворец Пуи', 'Последний император Китая Пуи жил в этом дворце как марионеточный правитель в эпоху Маньчжоу-го. Ныне это музей, рассказывающий о слежке и одиночестве, скрывавшихся за парадными залами. Дворец — тихое окно в бурную историю двадцатого века.'),
  'changchun/snow': ('Зимние развлечения', 'Долгие белоснежные зимы превращают Чанчунь в снежный праздник. Ледяные скульптуры светятся ночью разноцветными огнями, а лесное озеро Цзинъюэтань принимает лыжников и любителей санок. Несмотря на мороз, зима здесь — самое весёлое время года.'),
  'xining/lake': ('Озеро Цинхай', 'Цинхай — крупнейшее озеро Китая, раскинувшееся бирюзовым морем посреди плато. Летом его берега окружают золотые поля рапса, а на острова слетаются перелётные птицы. Велосипедный круг вокруг озера — любимое высокогорное приключение путешественников.'),
  'xining/monastery': ('Монастырь Кумбум', 'Кумбум — один из величайших монастырей тибетского буддизма, выросший на месте рождения Цонкапы, основателя школы гелуг. Его разноцветные скульптуры из ячьего масла, настенные росписи и тканевые аппликации славятся как «три искусства». Во дворах молитвенные барабаны паломников не останавливаются никогда.'),
  'xining/flower': ('Рапсовые поля', 'С приходом июля плато Цинхай до самого горизонта покрывается золотым цветением рапса. Берега озера и подножия гор колышутся тысячей оттенков жёлтого. В прохладном высокогорном воздухе это зрелище год за годом притягивает фотографов и молодожёнов.'),
  'xining/lamb': ('Вкусы плато', 'Стол Синина — место встречи кухонь хуэй и Тибета. Лапшу ручной вытяжки подают в дымящихся мисках, шашлычки из баранины потрескивают на углях, а ячий йогурт и чай с маслом — повседневные вкусы плато. По ночам рынки наполняются ароматом специй.'),
  'guilin/karst': ('Карстовые пейзажи реки Ли', 'Река Лицзян вьётся между известняковыми пиками, встающими из тумана, — именно этот пейзаж напечатан на банкноте в 20 юаней. Кораблики, плывущие из Гуйлиня в Яншо, бамбуковые плоты и рыбаки с бакланами создают живую китайскую картину.'),
  'guilin/elephant': ('Холм Слоновий Хобот', 'Эта скала, похожая на слона, опустившего хобот в реку Лицзян, — самый любимый символ Гуйлиня. Арка между хоботом и туловищем отражается в воде полной луной, за что её зовут «Пещерой воды и луны». Поэты слагают стихи об этом виде уже много столетий.'),
  'guilin/terrace': ('Рисовые террасы Лунцзи', 'Террасы Лунцзи — «Хребет дракона», ступень за ступенью обнимающие горные гряды, — плод многовекового труда народов чжуан и яо. Весной залитые водой террасы блестят, как зеркала, осенью они становятся золотыми. Деревянные деревни на вершинах хранят традиционный уклад.'),
  'guilin/osmanthus': ('Цветение османтуса', 'Имя Гуйлиня означает «лес османтуса», и осенью город утопает в сладком аромате этих крошечных цветов. Чай, вино и сладости из османтуса возглавляют список местных угощений. Прогулка под благоухающими деревьями вдоль реки — самый красивый ритуал сезона.'),
  'wenzhou/merchant': ('Вэньчжоуские купцы', 'Жители Вэньчжоу славятся как одно из самых предприимчивых сообществ Китая: через семейные и земляческие связи они строят торговые мосты от Европы до Америки. Город, первопроходец частного бизнеса в годы реформ, полон историй пути от маленькой мастерской до мирового рынка.'),
  'wenzhou/shoe': ('Обувная столица', 'Вэньчжоу считается обувной и кожевенной столицей Китая: огромная доля кожаной обуви в мире выходит из этого города-фабрики. Искусный и в мелких товарах — от зажигалок до очков, — город до сих пор хранит ремесленный дух эпохи, когда каждый дом был мастерской.'),
  'wenzhou/mountain': ('Горы Яньданшань', 'Горы Яньдан, знаменитые водопадами и острыми пиками, величают «первой горой у моря». Водопад Большого дракона с грохотом обрушивается со скал, а на закате силуэты некоторых вершин будто меняют очертания. Хребет охраняется как геопарк за уникальное геологическое строение.'),
  'wenzhou/seafood': ('Морепродукты', 'Кухня Вэньчжоу, открытого Восточно-Китайскому морю, лёгкая и свежая: кальмары, гребешки и рыба — основа повседневного стола. Местная кухня Оу позволяет вести собственному вкусу морепродуктов. Суп с рыбными шариками, отбитыми вручную, — самое любимое уличное блюдо города.'),
  'tangshan/memorial': ('Мемориальный парк землетрясения', 'Великое землетрясение 1976 года сровняло Таншань с землёй; в сегодняшнем мемориальном парке имена погибших высечены на длинных гранитных стенах. Каждый год у тихих водоёмов проходят церемонии памяти. Отстроенный заново город стал символом стойкости и возрождения.'),
  'tangshan/coal': ('Уголь и сталь', 'В Таншане открылись первая современная угольная шахта Китая и одна из первых железных дорог, здесь же построили первый в стране паровоз. Поэтому город считают колыбелью китайской промышленности. Культура угля и стали вплетена в его облик и поныне.'),
  'tangshan/ceramic': ('Таншаньская керамика', 'Таншань называют «фарфоровым городом севера»; особенно он славится костяным фарфором. Его тонкая, пропускающая свет белая посуда украшает столы по всему Китаю. Керамические ярмарки и мастерские умельцев поддерживают традицию в городе.'),
  'tangshan/lake': ('Парк Наньху', 'Наньху родилось, когда зону просадки старых шахт превратили в озеро и пышный парк; сегодня это зелёные лёгкие города. Вдоль берега тянутся велодорожки и цветники, а парк даже принимал крупную садоводческую выставку. Он стал символом примирения промышленного города с природой.'),
  'anshan/steel': ('Стальной город', 'В Аньшане расположен один из крупнейших сталелитейных комбинатов Китая, и город зовут «стальной столицей» страны. Поколениями зарево доменных печей освещало его ночи. Сталеварение здесь не просто ремесло, а сама идентичность города.'),
  'anshan/jade': ('Сюяньский нефрит', 'Сюянь в окрестностях Аньшаня — один из главных нефритовых краёв Китая. Во Дворце Нефритового Будды в городе хранится всемирно известная статуя Будды, вырезанная из единой колоссальной глыбы нефрита. Нефритовые мастерские и рынки полны мастерства, вдыхающего в камень жизнь.'),
  'anshan/mountain': ('Гора Цяньшань', 'Цяньшань, «Тысяча лотосовых пиков», — священная гора северо-востока: её гранитные вершины выстроились, как лепестки лотоса. По склонам рассыпаны буддийские и даосские храмы, а одна исполинская скала знаменита сходством с сидящим Буддой. Весной гора одевается цветами.'),
  'anshan/spring': ('Источники Танганцзы', 'У горячих источников Танганцзы ищут исцеления уже тысячу лет: поколения купались в минеральных водах и термальной грязи, которым приписывают силу облегчать боли в суставах. Принимавший в истории правителей и знаменитых гостей курорт и сегодня остаётся приютом для ищущих отдыха.'),
  'linyi/market': ('Оптовый рынок Линьи', 'Линьи — крупнейший оптовый торговый центр севера Китая: в его огромных рыночных павильонах найдётся всё, от иголки до мебели. Грузовики, отправляющиеся отсюда, развозят товары по всей стране. Эта кипучая жизнь принесла городу титул «логистической столицы».'),
  'linyi/brush': ('Мастер каллиграфии Ван Сичжи', 'Ван Сичжи, «мудрец каллиграфии» Китая, родился в Линьи; его плавным мазкам кисти подражают уже более тысячи лет. Мемориальный храм и фестивали каллиграфии в городе хранят его наследие. Запах туши в Линьи — изящный ответ гулу торговли.'),
  'linyi/mountain': ('Гора Мэншань', 'Мэншань, жемчужина хребта Имэн, — одна из высочайших гор Шаньдуна. Густые леса, водопады и кристально чистый воздух принесли ей звание «природного кислородного бара». С пешеходными тропами, горными деревушками и горным мёдом она дарит путешественникам тихое убежище.'),
  'linyi/pancake': ('Блин «Цзяньбин»', 'Тончайший блин из кукурузы и злаков — вековая основа стола горцев Имэна. Испечённый на раскалённой каменной плите, он традиционно съедается обёрнутым вокруг свежего зелёного лука. Сытный и долго хранящийся, этот хлеб был верным спутником суровой жизни горных деревень.'),
  'cangzhou/lion': ('Железный лев Цанчжоу', 'Гигантский чугунный лев, стоящий уже более тысячи лет, — гордый знак Цанчжоу и один из крупнейших древних железных памятников Китая. В народе его зовут «рыком, усмиряющим море»: говорят, его отлили, чтобы сдерживать наводнения. Город бережёт свой символ, как хранителя.'),
  'cangzhou/martial': ('Боевые искусства Цанчжоу', 'Цанчжоу славится как «родина ушу» Китая: здесь выросли жёсткие и действенные школы вроде бацзицюань. В прежние времена многие вооружённые охранники купеческих караванов были родом из этого города. Школы боевых искусств и турниры и сегодня держат традицию в силе.'),
  'cangzhou/canal': ('Великий канал', 'Великий канал, связывающий Пекин с Ханчжоу, проходит прямо через Цанчжоу, и веками город богател на канальной торговле. Старые пристани и портовые кварталы до сих пор хранят следы тех дней. Парки вдоль канала теперь любимое место вечерних прогулок.'),
  'cangzhou/jujube': ('Золотой финик', 'Тонкокожий, медово-сладкий унаби «золотая нить» из Цанчжоу величают королём сухофруктов. Своё имя он получил от тонких золотистых сладких нитей, тянущихся из мякоти, когда плод разламывают надвое. В пору осеннего урожая сады алеют, а чай и сладости из унаби — непременная часть местного стола.'),
  'nantong/textile': ('Текстильная столица', 'Современная текстильная история Наньтуна началась с хлопковых фабрик, основанных промышленником Чжан Цзянем. Сегодня город — столица домашнего текстиля Китая: его постельное бельё и шторы расходятся по мировым рынкам. Ткацкая культура живёт и в местном искусстве сине-белой набивной ткани.'),
  'nantong/mountain': ('Гора Ланшань', 'Пятиглавый Ланшань, встающий там, где Янцзы встречается с морем, — священная гора этих мест. Паломники и путешественники поднимаются по лестницам к многовековому буддийскому храму на вершине. Сверху под ногами разворачивается встреча великой реки с морем.'),
  'nantong/kite': ('Свистящий змей', 'Воздушные змеи «баньяо» из Наньтуна гудят в небе десятками маленьких свистков, закреплённых на каркасе; чем крепче ветер, тем громче звучит этот оркестр. Изготовление свистящих змеев — старинное ремесло, передаваемое из поколения в поколение и бережно хранимое местными мастерами.'),
  'nantong/school': ('Пионер образования', 'Промышленник и реформатор Чжан Цзянь посвятил своё состояние родному городу: он основал в Наньтуне современные школы, библиотеки и первый в Китае музей, созданный самим китайцем. Так город стал первопроходцем в образовании. Его идеал «спасения страны через промышленность» живёт в памяти горожан.'),
  'taizhou/opera': ('Мэй Ланьфан', 'Корни Мэй Ланьфана, легендарного мастера пекинской оперы, уходят в Тайчжоу; изящество, которое он привнёс в женские роли, открыло это искусство миру. Мемориальный парк и музей рассказывают его историю через костюмы и сценические фотографии. Мелодии оперы до сих пор звучат в парках города.'),
  'taizhou/tea': ('Утренний чай', 'Тайчжоу начинает день с «цзаоча»: к чайникам крепкого чая подают паровые пирожки, салат из тонко нарезанного сушёного тофу и суп с рыбными шариками. Утренний чай здесь не терпит спешки — соседи собираются в чайных и входят в день за неторопливой беседой.'),
  'taizhou/boat': ('Фестиваль лодок Циньтун', 'Каждую весну на заболоченных равнинах городка Циньтун собираются сотни лодок: гребцы состязаются под бой барабанов, и белая пена взлетает, когда шесты ударяют по воде. Этот многовековой лодочный праздник — самый ликующий день культуры водного края, внесённый в список национального наследия.'),
  'taizhou/meatball': ('Фрикаделька «Голова льва»', 'Большая нежная свиная тефтеля «львиная голова» — классика хуайянской кухни, названная так за пышную текстуру, напоминающую львиную гриву. Она часами томится на медленном огне и тает во рту. Вариант с крабовой икрой — самое почётное угощение осеннего стола.'),
  'jinhua/ham': ('Цзиньхуаский окорок', 'Ветчина Цзиньхуа созревает по многовековому методу засолки и вяления на воздухе; тёмно-красный срез и глубокий аромат сделали её самой знаменитой ветчиной Китая. Чаще всего её используют, чтобы придать глубину супам и тушёным блюдам. Хорошая цзиньхуаская ветчина — плод многолетнего терпения.'),
  'jinhua/film': ('Киностудия Хэндянь', 'Хэндянь в окрестностях Цзиньхуа — крупнейшая в мире съёмочная площадка под открытым небом, где возвышаются гигантские копии Запретного города и древних дворцов. Здесь снимают бесчисленные исторические фильмы и сериалы. Гуляя по декорациям, посетители запросто могут встретить актёров в полном костюме.'),
  'jinhua/cave': ('Пещера Шуанлун', 'Вход в пещеру Шуанлун, «Двойной дракон», незабываем: посетители вплывают на лодке, лёжа на спине под низкими каменными вратами. Внутри открывается прохладный подземный мир, украшенный сталактитами и сталагмитами. Пещеру с восхищением описывали ещё путешественники древности.'),
  'jinhua/bridge': ('Древние мосты', 'Окрестности Цзиньхуа, звавшегося в старину Учжоу, усеяны арочными каменными мостами и городками на воде, пронизанными каналами. Белостенные дома с чёрной черепицей отражаются в воде, а у мостов теснятся чайные. Этот пейзаж доносит до наших дней изящный уклад жизни Цзяннани.'),
  'wuhu/park': ('Парк развлечений Фантэ Вондерленд', 'В Уху расположен целый кластер крупнейших тематических парков Китая: от американских горок до миров анимации, они дарят семьям дни, полные восторга. Так город вырос в развлекательную столицу региона — по выходным сюда стекаются потоки гостей из соседних провинций.'),
  'wuhu/ironart': ('Железная живопись', 'В искусстве «железной живописи» Уху кованое железо превращается в изящные картины, напоминающие мазки кисти; этому ремеслу около трёх веков, и оно переносит дух туши на металл. Молотом и наковальней мастера создают горы, сосны и птиц. Эти работы — самый самобытный подарок города.'),
  'wuhu/rice': ('Рисовый порт', 'Уху исторически был одним из крупнейших рисовых рынков Китая: благодаря положению на Янцзы урожай юга переходил из рук в руки именно здесь. Грузчиков с мешками на пристанях сменили современные склады, но город по-прежнему гордится наследием зерновой торговли.'),
  'wuhu/river': ('Порт на реке Янцзы', 'Оживлённый порт на Янцзы делает Уху воротами провинции Аньхой в большой мир. Грузовые суда и контейнерные краны вдоль реки не знают отдыха, и за этим движением приятно наблюдать из прибрежных парков. Река несёт городу и торговлю, и вечернюю прохладу.'),
  'huangshan/peak': ('Хуаншань (Жёлтые горы)', 'С гранитными пиками, морем облаков, причудливыми соснами и горячими источниками Хуаншань — самая знаменитая гора Китая и объект ЮНЕСКО. Эти «четыре чуда» веками вдохновляют художников и поэтов. Стоять над облаками на рассвете — воспоминание на всю жизнь.'),
  'huangshan/village': ('Деревня Хунцунь', 'Хунцунь — хуэйская деревня с белыми стенами и чёрной черепицей, пронизанная водными каналами и украшенная прудом в форме полумесяца, — будто сошла с картины и внесена в список ЮНЕСКО. Её план задуман так, чтобы повторять очертания быка. Когда утренний туман ложится на озеро, художники расставляют мольберты вдоль берега.'),
  'huangshan/tea': ('Чай Маофэн', 'Хуаншань Маофэн, собираемый на туманных склонах, — один из самых знаменитых зелёных чаёв Китая; имя ему дали пушистые листья в форме горных пиков. Выше всего ценится ранневесенний сбор. В чашке он оставляет лёгкую орхидейную ноту — будто облака горы вплетены в лист.'),
  'huangshan/ink': ('Хуэйчжоуские чернила и искусство', 'Старинный край Хуэйчжоу создавал самые почитаемые в Китае тушевые бруски и каменные тушечницы, которые каллиграфы ищут веками. Усадьбы, украшенные резьбой по дереву, кирпичу и камню, рождены тем же духом ремесла. Культура Хуэй соединяет тушь и архитектуру в единой эстетике.'),
  'yichun/moon': ('Гора Минъюэ', 'Гора Минъюэ, чьё имя означает «Ясная луна», — символ Ичуня, города, известного и своими лунными праздниками. Канатная дорога поднимает гостей к тропам вдоль обрывов и высокогорным лугам. Когда на вершине расступается туман, долины внизу сияют серебристым светом.'),
  'yichun/spring': ('Горячие источники', 'Горячие источники городка Вэньтан под Ичунем богаты редким селеном и издавна считаются целебными. Курортные отели и бассейны под открытым небом принимают гостей круглый год. Союз горного воздуха и горячей воды сделал город одним из любимых термальных курортов Китая.'),
  'yichun/zen': ('Чань-буддизм', 'Горы Ичуня — из тех земель, где укоренились важные школы китайского чань-буддизма (дзен); по тихим долинам рассыпаны многовековые храмы. Чайные сады монахов и залы для медитации приглашают гостей замедлиться. Звон колоколов эхом разносится по туманному лесу.'),
  'yichun/rice': ('Рисовая равнина', 'Плодородная равнина реки Юань издавна была житницей Цзянси: её обильно орошаемые поля год за годом дают богатый урожай риса. Пора жатвы проходит в деревнях, как праздник. Местная лапша из свежего риса и рисовое вино приносят щедрость равнины на стол.'),
  'zhangzhou/narcissus': ('Нарциссы', 'Самые знаменитые в Китае луковицы нарциссов выращивают в Чжанчжоу, а сам цветок — непременное украшение Праздника весны. Мастера делают на луковицах особые надрезы, чтобы цветы распускались в изящных формах. Нарцисс, расцветший дома к Новому году, считается благословением на весь год.'),
  'zhangzhou/tulou': ('Тулоу (Земляные дома хакка)', 'Гигантские круглые крепости-дома из утрамбованной земли — «тулоу» — собирают целую деревню под одной крышей и внесены в список ЮНЕСКО. Толстые стены дают и защиту, и прохладу, а общинная жизнь в их дворах продолжается веками. Группы тулоу среди зелёных холмов рисуют сказочный пейзаж.'),
  'zhangzhou/banana': ('Тропические фрукты', 'Тёплая влажная дельта Чжанчжоу плодоносит круглый год: банановые плантации, рощи лонгана и мандариновые сады тянутся до горизонта. Крупное сочное помело этих мест — тоже любимец стола. В любой сезон фруктовые рынки — буйство красок и ароматов.'),
  'zhangzhou/coast': ('Остров Дуншань', 'Остров Дуншань с золотыми пляжами и рыбацкими деревнями — жемчужина южного побережья. Его самая знаменитая достопримечательность — гигантский «камень, качаемый ветром», балансирующий на краю обрыва: говорят, он слегка покачивается на ветру. Вечерами лодки, возвращаясь в гавань, привозят свежий улов дня.'),
  'guangzhou/tower': ('Кантонская телебашня', 'Башня, поднимающаяся на берегу Жемчужной реки, за свой стройный изогнутый силуэт получила в народе прозвище «Тонкая талия». Одна из самых высоких башен мира, после наступления темноты она переливается тысячами светодиодных огней и считается современной короной силуэта Гуанчжоу с видами на всю дельту.'),
  'guangzhou/dimsum': ('Утренний чай (Ямча)', 'Утро в Гуанчжоу начинается с «юм ча»: к крепкому чаю подают димсамы, приготовленные на пару в бамбуковых корзинках. Пельмени с креветками, сяомай и хрустящая выпечка сопровождают беседы, которые тянутся часами, — этот ритуал считается душой кантонской кухни.'),
  'guangzhou/academy': ('Академия клана Чэнь', 'Этот величественный родовой зал, построенный в конце эпохи Цин на средства семей с фамилией Чэнь, славится резьбой по дереву, каменными рельефами и разноцветными керамическими фигурами, усеивающими его крыши. Сегодня здесь работает музей народного искусства, показывающий вершину южнокитайского ремесла.'),
  'guangzhou/flower': ('Город цветов', 'Благодаря мягкому климату цветы в Гуанчжоу распускаются круглый год, поэтому с древних времён его называют «Городом цветов». Перед китайским Новым годом улицы заполняют огромные цветочные ярмарки, где семьи покупают кумкватовые деревца и ветви персика, чтобы принести в дом удачу.'),
  'wuhan/crane': ('Башня Жёлтого Журавля', 'Башня Жёлтого журавля, глядящая на Янцзы, ведёт свою историю с эпохи Троецарствия и входит в число самых знаменитых башен Китая. Воспетая в стихах Цуй Хао и Ли Бо, она много раз разрушалась и отстраивалась заново, но всегда сохраняла свою поэтическую душу.'),
  'wuhan/noodle': ('Лапша жэганьмянь', 'Жэганьмянь, «горячая сухая лапша», готовится из упругой отварной лапши, заправленной кунжутной пастой, соленьями и зелёным луком. Уханьцы начинают день с миски, купленной у уличного лотка: завтрак здесь так любим, что для него есть особое слово — «гоцзао», целый образ жизни.'),
  'wuhan/duckneck': ('Острая утиная шея', 'Утиные шейки, часами тушённые в ароматном бульоне с перцем чили и пряностями, — самая любимая закуска Уханя. Это острое, слегка обжигающее лакомство обгладывают прямо с косточки: без него не обходятся ни беседы на берегу реки, ни холодное пиво долгими летними вечерами.'),
  'wuhan/university': ('Цветение сакуры в Уханьском университете', 'Каждую весну исторический кампус Уханьского университета скрывается под облаками розово-белой сакуры, привлекая гостей со всего Китая. Цветение на фоне старинных корпусов на склонах горы Лоцзя создаёт самый романтичный весенний пейзаж города.'),
  'tianjin/eye': ('Колесо обозрения «Тяньцзиньский глаз»', 'Гигантское колесо обозрения, установленное прямо посреди моста через реку Хайхэ, — одно из редких в мире колёс, вращающихся над текущей водой. С вершины оба берега открываются разом: с одной стороны — фасады европейской эпохи, с другой — сверкающие стеклянные башни.'),
  'tianjin/baozi': ('Баоцзы «Гоубули»', 'Паровые пирожки Гоубули, которые готовят со времён эпохи Цин, славятся тонким тестом, сочной мясной начинкой и аккуратно защипанными складками — это фирменный вкус Тяньцзиня. Странное название означает «даже собака не обратит внимания»: по легенде, основатель так увлекался лепкой, что ему было некогда разговаривать с покупателями.'),
  'tianjin/crosstalk': ('Сяншэн', 'Сяншэн — традиционное сценическое искусство, в котором два комика смешат публику стремительными словесными дуэлями, каламбурами и пародиями. Укоренившись в чайных Тяньцзиня, этот жанр принёс городу славу колыбели китайской комедии, и его до сих пор смотрят за чашкой горячего чая.'),
  'tianjin/architecture': ('Пять Великих Проспектов', 'Удадао, «Пять великих улиц», хранит сотни вилл в европейском стиле, оставшихся с эпохи иностранных концессий. Квартал, где британский, французский и итальянский стили стоят бок о бок, принёс Тяньцзиню прозвище «музей мировой архитектуры»; осматривать его принято в экипаже или на велосипеде.'),
  'xiamen/island': ('Остров Гуланъюй', 'На острове Гуланъюй близ Сямэня нет автомобилей: в узких переулках слышны лишь шаги и звуки фортепиано. Со старыми зданиями консульств и виллами, увитыми бугенвиллеей, этот остров из списка Всемирного наследия ЮНЕСКО — музей под открытым небом, куда добираются коротким паромом.'),
  'xiamen/piano': ('Остров фортепиано', 'Западная музыка пустила корни на Гуланъюе в девятнадцатом веке вместе с поселившимися там миссионерами и купцами. Прославившийся необычайным числом фортепиано на семью, «Остров пианино» хранит традицию: здесь есть музей фортепиано и целые поколения музыкантов.'),
  'xiamen/egret': ('Белая цапля', 'Старое имя Сямэня — «Лудао», «остров цапель», и изящные белые цапли и сегодня парят над его берегами и лагунами. Ставшая символом города птица встречается повсюду — от скульптур до названий улиц — и напоминает о тесной связи Сямэня с морем и природой.'),
  'xiamen/oyster': ('Омлет с устрицами', 'Свежие устрицы, смешанные с яйцом и крахмалом из батата и обжаренные до хрустящей корочки и нежной середины, — уличная классика побережья Миньнань. На ночных рынках Сямэня этот омлет подают с кисло-острым соусом, и его так же горячо любят по другую сторону пролива, на Тайване.'),
  'harbin/ice': ('Харбинский фестиваль льда', 'Каждую зиму из гигантских блоков льда, вырезанных из замёрзшей Сунгари, строят дворцы, башни и горки, которые ночью сияют яркими красками. Харбинский фестиваль льда и снега — крупнейший в мире фестиваль ледяных скульптур, превращающий морозный город в сказку для миллионов гостей.'),
  'harbin/cathedral': ('Софийский собор', 'Софийский собор с зелёным луковичным куполом и стенами из красного кирпича — самое величественное наследие русской железнодорожной эпохи Харбина. Сегодня в нём располагается музей архитектуры, а площадь перед собором, с голубями и уличными музыкантами, — любимое место встреч горожан.'),
  'harbin/sausage': ('Красная колбаса', 'Копчёная красная колбаса, которую больше века назад начали делать по рецептам русских переселенцев, — фирменный вкус Харбина. Аромат древесного дыма и лёгкая чесночная нота прекрасно сочетаются со свежим хлебом и холодным пивом, принося европейские корни города прямо на стол.'),
  'harbin/accordion': ('Музыкальный город', 'Скрипки, аккордеоны и оперная культура прибыли с русскими переселенцами, сделав Харбин одним из первых центров западной музыки в Китае. Город, где родился первый в стране симфонический оркестр, поддерживает звание «города музыки» давним летним музыкальным фестивалем.'),
  'fuzhou/alley': ('Три переулка и семь аллей', 'Квартал «Три улицы и семь переулков» сохранил дома с белёными стенами и чёрной черепицей эпох Мин и Цин. Когда-то в его узких каменных переулках жили учёные и государственные мужи; сегодня в усадьбах с внутренними двориками работают чайные и ремесленные лавки — это живой музей старого города.'),
  'fuzhou/banyan': ('Город баньянов', 'Благодаря озеленению, начатому ещё в эпоху Сун, улицы Фучжоу заполнились баньянами, стоящими уже многие века. Их воздушные корни свисают, словно длинные бороды, и дарят густую прохладную тень в знойное влажное лето — потому город ласково называют «Жунчэн», «Город баньянов».'),
  'fuzhou/hotspring': ('Горячие источники', 'Природные горячие источники бьют прямо в центре Фучжоу, питая банную культуру, которой больше тысячи лет. Горожане и сегодня снимают усталость в районных купальнях: построенный прямо над геотермальным сокровищем Фучжоу — одна из редких «столиц горячих источников» Китая.'),
  'fuzhou/soup': ('Будда перепрыгивает через стену', 'Фотяоцян — легендарный суп, в котором десятки ценных ингредиентов, от гребешков до грибов, часами томятся в глиняном кувшине. Название происходит из стихов, где говорится, что аромат так неотразим, что даже монах перепрыгнул бы через стену, чтобы его отведать; это блюдо считается венцом фуцзяньской кухни.'),
  'dongguan/robot': ('Фабрика мира', 'Дунгуань в сердце дельты Жемчужной реки — промышленный гигант, на фабриках которого производится заметная доля мировой электроники и игрушек. Трудоёмкие конвейеры постепенно уступают место умным заводам и роботизированным манипуляторам: «фабрика мира» обновляет себя для новой эпохи.'),
  'dongguan/basketball': ('Баскетбольный город', 'Баскетбол в Дунгуане — настоящая страсть: площадка есть почти в каждом квартале, а от дворовых игр к профессиональной лиге ведёт мощная система подготовки. Здесь играет «Гуандун Саузерн Тайгерс», один из самых титулованных клубов китайской лиги, и город официально провозглашён «городом баскетбола».'),
  'dongguan/keyuan': ('Сад Кэюань', 'Сад Кэюань, построенный чиновником эпохи Цин, знаменит тем, как мастерски на крошечном участке разместились павильоны, пруды и извилистые галереи. Один из четырёх великих классических садов Гуандуна, Кэюань в концентрированном виде передаёт утончённость южнокитайского ландшафтного искусства.'),
  'dongguan/cannon': ('Форты Хумынь', 'Крепости Хумэнь когда-то охраняли устье Жемчужной реки рядами пушек. Именно на этом берегу в 1839 году комиссар Линь Цзэсюй уничтожил конфискованный опиум, что разожгло Опиумную войну; сегодня батареи и музей рассказывают об этом переломном моменте новой истории Китая.'),
  'lanzhou/beefnoodle': ('Ланьчжоуская говяжья лапша', 'Ланьчжоуская лапша ручной вытяжки следует знаменитой формуле: прозрачный говяжий бульон, белая редька, красное масло чили и зелёная кинза. Мастера на глазах у посетителей за секунды растягивают тесто в тонкие нити; утренняя миска — ежедневный ритуал города и одна из самых знаменитых лапш Китая.'),
  'lanzhou/waterwheel': ('Водяные колёса', 'Гигантские деревянные водяные колёса, построенные в эпоху Мин, чтобы поднимать воду Хуанхэ на поля, стали символом Ланьчжоу. В прибрежном парке водяных колёс точные копии этих вековых чудес инженерной мысли вращаются и сегодня, а их тяжёлый скрип доносит голос прошлых времён.'),
  'lanzhou/statue': ('Мать-река Хуанхэ', 'Скульптура «Мать — Жёлтая река» на набережной изображает мать с волнистыми волосами и младенца, лежащего у её груди. Мать воплощает Хуанхэ, вскормившую китайскую цивилизацию, а дитя — народ, рождённый её водами; это самое проникновенное выражение связи Ланьчжоу с рекой.'),
  'lanzhou/raft': ('Плот из овечьих шкур', 'Плоты из надутых овечьих шкур, привязанных к деревянной раме, веками перевозили грузы и людей по Жёлтой реке. Сегодня эти традиционные плоты катают гостей вдоль набережной Ланьчжоу, и скольжение по мутным водам остаётся самым аутентичным впечатлением города.'),
  'urumqi/bazaar': ('Гранд-базар', 'Большой базар Урумчи с башней в духе исламской архитектуры и купольными галереями хранит дух торговли Шёлкового пути. Прилавки ломятся от сухофруктов, специй, шёлка и ножей ручной работы, а по вечерам площадь оживает музыкой и танцевальными представлениями.'),
  'urumqi/tianshan': ('Озеро Тяньчи', 'Тяньчи, «Небесное озеро», лежит в горах Тяньшаня в тени снежного пика Богдо и славится своей глубокой синевой в обрамлении еловых лесов. По легенде, здесь устраивала пиры Владычица Запада Сиванму; озеро входит в тяньшаньский объект Всемирного наследия ЮНЕСКО.'),
  'urumqi/kebab': ('Уйгурский шашлык из баранины', 'Шампуры с бараниной, шипящие над углями, посыпают зирой и хлопьями чили, и их дымный аромат окутывает улицы Урумчи. Кебаб, символ уйгурской кухни, лучше всего вкушать на ночном рынке со свежей лепёшкой нан из тандыра и чайником крепкого чая.'),
  'urumqi/dance': ('Уйгурский танец', 'Уйгурские танцы, кружащиеся под бой барабанов и струны равапа и дутара, — украшение каждой свадьбы и праздника. С изящными движениями рук и всё ускоряющимися вращениями это радостное, общее искусство: гостей непременно втягивают в круг, чтобы они присоединились к танцу.'),
  'haikou/coconut': ('Кокосовый город', 'В Хайкоу, столице острова Хайнань, проспекты укрыты тенью кокосовых пальм, отсюда и прозвище «Ечэн» — «Кокосовый город». Уличные торговцы одним взмахом мачете вскрывают охлаждённые кокосы, предлагая самое естественное лекарство от тропической жары.'),
  'haikou/arcade': ('Аркады Цилоу', 'Старые торговые улицы Хайкоу украшают «цилоу» — дома-лавки с аркадами, построенные купцами, вернувшимися из Юго-Восточной Азии. Их крытые галереи вот уже около века укрывают покупателей от тропических ливней и палящего солнца — изящная архитектура тени.'),
  'haikou/crater': ('Вулканические кратеры', 'Древнее вулканическое поле у самого Хайкоу превратилось в зелёный геопарк с потухшими кратерами и лавовыми туннелями. Базальт, оставшийся от давних извержений, до сих пор используется в домах и оградах местных деревень, а в жерло кратера можно спуститься пешком.'),
  'haikou/turtle': ('Тропическое море', 'Тёплые прозрачные воды у берегов Хайнаня питают коралловые рифы и луга морской травы, полные жизни. Морские черепахи кормятся и откладывают яйца на этих берегах, и благодаря природоохранным проектам бег черепашат к прибою снова стал обнадёживающим зрелищем.'),
  'luoyang/grotto': ('Гроты Лунмэнь', 'Гроты Лунмэнь, высеченные в скалах по обоим берегам реки Ихэ, хранят десятки тысяч буддийских статуй и внесены в список ЮНЕСКО. Начатые в эпоху Северной Вэй и достигшие расцвета при Тан, резные работы венчает колоссальный будда Вайрочана с безмятежной улыбкой.'),
  'luoyang/peony': ('Столица пионов', 'Со времён династии Тан Лоян неразрывно связан с пионами: по легенде, этот цветок сослали сюда за отказ подчиниться приказу императрицы У Цзэтянь расцвести зимой. Каждый апрель город взрывается красками на фестивале пионов, чествуя цветок, который традиция венчает «королём цветов».'),
  'luoyang/whitehorse': ('Храм Белой Лошади', 'Храм Белой лошади, основанный в 68 году нашей эры, почитается как первый буддийский храм Китая. Своё имя он получил в честь белой лошади, которая, по преданию, привезла священные писания из Индии. Символ прихода буддизма в страну, храм и сегодня остаётся действующим местом молитвы и паломничества.'),
  'luoyang/capital': ('Древняя столица', 'Лоян служил столицей тринадцати династиям, включая Хань и Тан, находясь в самом центре китайской истории. Этот древний город в бассейне Хуанхэ был восточной точкой Шёлкового пути, а его музеи и руины хранят тысячелетнюю императорскую память.'),
  'shantou/gongfutea': ('Чай гунфу', 'Чай гунфу района Чаошань — церемониальное искусство заваривания: крошечные чашки наполняются, опустошаются и наполняются вновь в тщательно выверенных кругах. Предложить гостю чай здесь — глубочайшее выражение уважения, а порядок трёх чашек и точные движения рук бережно передаются из поколения в поколение.'),
  'shantou/beefpot': ('Чаошаньский хого с говядиной', 'Чаошаньский говяжий хого славится преданностью свежести: мясо дневного забоя разбирают по отрубам и опускают в кипящий прозрачный бульон буквально на секунды. У каждого ломтика своё точное время варки; мясо макают в ореховый соус сатэ, подчёркивающий его природную сладость.'),
  'shantou/opera': ('Чаошаньская опера', 'Чаошаньская опера с многовековой историей известна изящными мелодиями на чаошаньском диалекте и роскошными расшитыми костюмами. Вместе с эмигрантами из Чаошаня это сценическое искусство распространилось по Юго-Восточной Азии и поколениями хранило самобытность общины.'),
  'shantou/harbor': ('Порт Шаньтоу', 'Порт Шаньтоу, открытый для внешней торговли в девятнадцатом веке, стал воротами, через которые бесчисленные чаошаньцы уезжали за океан. Корни многих китайских семей Юго-Восточной Азии тянутся сюда; свидетельство этой связи — письма «цяопи», которые эмигранты посылали домой.'),
  'baoding/mansion': ('Резиденция наместника', 'Резиденция наместника Чжили в эпоху Цин была ставкой губернаторов, управлявших провинцией Чжили, окружавшей императорскую столицу. Здесь служили такие влиятельные деятели, как Ли Хунчжан и Юань Шикай, а хорошо сохранившиеся дворы и залы — живой документ имперского провинциального управления.'),
  'baoding/donkeyburger': ('Ослиный бургер', '«Люйжоу хошао», сэндвич с ослиным мясом, готовят, наполняя хрустящую лепёшку прямо из печи медленно тушённым пряным мясом. Это лакомство, воспетое местной поговоркой «на небе — мясо дракона, на земле — мясо осла», — самая знаменитая уличная еда Баодина и предмет его гордости.'),
  'baoding/balls': ('Баодинские шары здоровья', 'Металлические баодинские шары, которые вращают в ладони, — традиционный снаряд для упражнения рук, изготавливаемый со времён эпохи Мин. Звуковые пластины внутри при вращении издают два тона — высокий и низкий; считается, что регулярные занятия развивают гибкость пальцев и спокойствие ума.'),
  'baoding/reeds': ('Байяндянь', 'Байяндянь, одно из крупнейших водно-болотных угодий Северного Китая, состоит из сотен озерков, соединённых протоками в зарослях тростника. Летом расцветают лотосы, камыши звенят птичьими голосами, а жители деревень на узких лодках ловят рыбу и срезают тростник; край называют «Жемчужиной Севера».'),
  'jilin/rime': ('Цзилиньский иней', 'Зимними ночами пар, поднимающийся над незамерзающей Сунгари, оседает на прибрежных деревьях кристально-белым инеем. Это явление, называемое «усун», причисляют к четырём великим чудесам природы Китая; на утреннем солнце серебристые деревья сверкают, как в сказке.'),
  'jilin/snowboard': ('Горнолыжный курорт', 'Благодаря долгим снежным зимам Гирин — один из ведущих регионов зимнего спорта в Китае. Современные курорты в окрестных горах привлекают лыжников и сноубордистов сухим пушистым снегом, и именно этот край воспитал значительную часть зимних спортсменов страны.'),
  'jilin/meteorite': ('Музей метеоритов', 'В 1976 году в небе над Гирином распался метеорит, устроив один из крупнейших зарегистрированных каменных метеоритных дождей. Главный фрагмент весом более тонны сегодня выставлен в городском музее метеоритов, где посетители могут взглянуть в лицо этому гостю из космоса.'),
  'jilin/skate': ('Замёрзшая река Сунхуа', 'С приходом зимы тихие участки Сунгари покрываются толстым льдом и превращаются в народный каток под открытым небом. Конькобежцы скользят, на льду крутят волчки, дети наперегонки катаются на санках — в холодные месяцы набережная становится самым весёлым местом встреч Гирина.'),
  'ordos/khan': ('Мавзолей Чингисхана', 'Мавзолей Чингисхана в степи Ордоса — святилище памяти великого хана под тремя куполами в форме монгольских юрт. Стражи-дархаты веками поддерживают здесь церемониальный огонь и подношения, делая мавзолей одним из самых священных центров монгольской культуры.'),
  'ordos/cashmere': ('Кашемир', 'Тонкий подшёрсток коз, закалённых суровыми зимами ордосской степи, даёт один из лучших кашемиров в мире. Это волокно, называемое «мягким золотом», сделало город мировым центром производства кашемира, превратив пастушескую традицию в современную индустрию роскоши.'),
  'ordos/sanddune': ('Поющие пески', 'Гигантские дюны пустыни Кубучи издают глубокий гул, когда с них скатываешься, — потому их называют «поющими песками». Гости пересекают дюны на верблюжьих караванах или катаются на сэндбордах, а когда закатное солнце окрашивает песок золотом, пустыня превращается в тихую поэзию.'),
  'ordos/yurt': ('Монгольская юрта', 'Круглая монгольская юрта, покрытая белым войлоком, устроена так, чтобы выдерживать степные ветры и при этом легко разбираться для перекочёвки. Её дверь смотрит на юг, а очаг в центре — сердце семейной жизни; ночёвка в юрте в ордосской степи — лучший способ ощутить гостеприимство кочевников.'),
  'jining/confucius': ('Храм Конфуция', 'Цюйфу, входящий в состав Цзинина, — город, где родился великий мудрец Конфуций. Посвящённый ему храм, усадьба рода Кун и лесистое семейное кладбище вместе внесены в список ЮНЕСКО; кипарисовые дворы и древние стелы — молчаливые свидетели более чем двух тысячелетий почитания.'),
  'jining/barge': ('Великий канал', 'Цзинин, оживлённый порт на Великом канале, соединяющем Пекин и Ханчжоу, веками процветал благодаря зерновым баржам и купеческим потокам. Канальная торговля принесла городу богатство и живую портовую культуру, а южные участки великого водного пути перевозят грузы и сегодня.'),
  'jining/sword': ('Ляншаньские герои', 'В классическом романе «Речные заводи» 108 героев, пострадавших от несправедливости, собираются на окружённых болотами холмах Ляншаня. Во главе с Сун Цзяном эти благородные разбойники сражаются за бедняков против угнетателей. Сегодня Ляншань — культурная достопримечательность, оживляющая сцены романа.'),
  'jining/fishnet': ('Озеро Вэйшань', 'Вэйшань, одно из крупнейших пресноводных озёр Северного Китая, летом укрывается полями лотосов, уходящими к горизонту. Рыбацкие семьи забрасывают сети способами, передаваемыми из поколения в поколение, и живут в ритме озера, а местная кухня превозносит свежую рыбу и хрустящий корень лотоса.'),
  'langfang/culture': ('Культурный центр Шёлкового пути', 'Огромный современный культурный центр Ланфана, расположенного между Пекином и Тяньцзинем, собирает под одной крышей выставки на тему Шёлкового пути, сценические искусства и ремёсла. Здание, вдохновлённое эстетикой старинных караванных дорог, символизирует роль города как культурного моста между двумя мегаполисами.'),
  'langfang/furniture': ('Мебельный город', 'Уезд Сянхэ в составе Ланфана — один из крупнейших в Китае центров производства и торговли мебелью. В магазинах и мастерских, тянущихся на километры, найдётся всё — от классической работы по палисандру до современного дизайна; сюда съезжаются семьи со всего Северного Китая, обустраивающие дом.'),
  'langfang/tunnel': ('Древние военные туннели', 'В пограничной полосе между империей Сун и северным государством Ляо под землёй были прорыты тайные сети оборонительных туннелей. Эти выложенные кирпичом ходы с вентиляционными шахтами и засадными камерами стоят уже около тысячи лет — подземные свидетели древних пограничных войн.'),
  'langfang/themepark': ('Парк «Первый город»', '«Тянься Диъи Чэн», «Первый город Поднебесной», — огромный тематический парк, с размахом воссоздающий стены и ворота старого Пекина. С храмовыми ярмарками, традиционными представлениями и классической архитектурой он отправляет семьи в путешествие в имперское прошлое столицы.'),
  'yancheng/salt': ('Город Соли', 'Имя Яньчэна означает «город соли»: его прибрежные солеварни веками наполняли императорскую казну. Соль, добываемая выпариванием морской воды на солнце, определила судьбу города, и это наследие живёт сегодня в музеях, топонимах и местных преданиях.'),
  'yancheng/crane': ('Японский журавль', 'Прибрежные водно-болотные угодья Яньчэна — крупнейшая в мире зимовка диких японских журавлей. Эти величавые птицы, символ долголетия и изящества в китайской культуре, каждую зиму прилетают сюда с севера, и их неспешный полёт над тростниками завораживает любителей природы.'),
  'yancheng/elk': ('Олень Давида', 'Олень милу когда-то полностью исчез из дикой природы Китая, уцелев лишь в зарубежных парках. Возвращённые в заповедник Дафэн в Яньчэне олени размножились, и сегодня крупнейшее в мире стадо милу свободно бродит по этим влажным прибрежным лугам — настоящий триумф охраны природы.'),
  'yancheng/wetland': ('Прибрежное водно-болотное угодье', 'Приливные отмели побережья Жёлтого моря — гигантская остановка на пути перелётных птиц, внесённая в список Всемирного наследия ЮНЕСКО. Миллионы куликов, следующих восточноазиатско-австралазийским пролётным путём, отдыхают и кормятся здесь, наполняя илистые отмели шелестом крыльев весной и осенью.'),
  'huzhou/brush': ('Кисть Ху', 'Кисть ху, изготавливаемая в Хучжоу, — самая почитаемая из китайских кистей, одна из «четырёх драгоценностей кабинета». Наконечники из волоса козы, кролика и колонка проходят десятки кропотливых этапов, становясь одновременно острыми и упругими; для каллиграфов их ценность неизмерима.'),
  'huzhou/bamboo': ('Бамбуковое море Аньцзи', 'Бамбуковые леса, укрывающие холмы уезда Аньцзи, колышутся на ветру, как бескрайнее зелёное море. Ставшие декорацией незабываемых сцен фильма «Крадущийся тигр, затаившийся дракон», они дарят гостям прохладный воздух, пешеходные тропы и местную кухню с нежными побегами бамбука.'),
  'huzhou/silkworm': ('Шелководство', 'Хучжоу на южном берегу озера Тайху — тысячелетнее сердце тутового шелководства. Традиционная система, соединяющая тутовые сады с рыбными прудами, признана сегодня объектом всемирного сельскохозяйственного наследия, а хучжоуский шёлк на протяжении истории одевал императоров и их дворы.'),
  'huzhou/whitetea': ('Белый чай Аньцзи', 'Белый чай из Аньцзи на самом деле зелёный: его делают из редкого сорта, весенние листья которого настолько бледны, что кажутся почти белыми. Любимец ценителей за мягкий сладковатый свежий вкус и низкую терпкость, он имеет столь короткий сезон сбора, что стал одним из самых желанных чаёв Китая.'),
  'quzhou/go': ('Го (Вэйци)', 'По легенде, дровосек на горе Ланькэ так засмотрелся на партию в го двух бессмертных, что не заметил, как пролетели века и сгнило топорище его топора. Благодаря этому преданию Цюйчжоу почитается священной родиной го, и древняя стратегическая игра живёт в городе с большим воодушевлением.'),
  'quzhou/peaks': ('Пики Цзянлан', 'Три исполинских каменных столба горы Цзянланшань отвесно вздымаются к небу из зелёного леса. Выдающийся образец рельефа «данься» из красного песчаника, гора внесена в список Всемирного наследия ЮНЕСКО, а прогулка по узкой расщелине между столбами захватывает дух.'),
  'quzhou/ponkan': ('Цюйчжоуский понка́н', 'Мандарины понкан, растущие на мягких холмах Цюйчжоу, славятся легко снимающейся кожурой и сладкими, как мёд, дольками. В конце осени сады вспыхивают оранжевым; сбор урожая собирает семьи среди деревьев, а мандарины становятся радостью зимних столов всей округи.'),
  'quzhou/cake': ('Запечённая лепёшка', 'Печёную лепёшку Цюйчжоу готовят, прилепляя кружки дрожжевого теста к раскалённой внутренней стенке печи-бочки. Под хрустящей корочкой в кунжуте прячется пряная начинка, а утренняя очередь у пекарни показывает, как горячо местные любят это начало дня.'),
  'huainan/tofu': ('Родина тофу', 'По преданию, тофу родился в эпоху Хань, когда алхимики принца Лю Аня на горе Багуншань впервые сквасили соевое молоко. Изобретённое здесь около двух тысяч лет назад, это скромное блюдо разошлось по кухням всего мира, и Хуайнань чествует наследие ежегодным фестивалем тофу.'),
  'huainan/coalmine': ('Угольный город', 'Построенный над богатыми угольными пластами Хуайнань издавна служит энергетической базой Восточного Китая. Шахты и электростанции питают региональную сеть, а город тем временем превращает старые горные выработки в озёра и парки, направляя индустриальное наследие к зелёному будущему.'),
  'huainan/oldtown': ('Древний город Шоусянь', 'Древний город уезда Шоусянь — один из редких китайских городов, чьи стены эпохи Сун сохранились целиком. Толстые кирпичные валы и арочные ворота защищали город даже от наводнений, а старые улицы внутри стен хранят следы царства Чу, устроившего здесь свою последнюю столицу.'),
  'huainan/classic': ('Хуайнань-цзы', '«Хуайнань-цзы» — философский классик, составленный учёными при дворе Лю Аня, князя Хуайнани, в эпоху Хань. Соединяя даосскую мысль, космологию и искусство управления государством, трактат донёс до нас и любимые легенды — например, о богине Нюйве, починившей разбитое небо.'),
  'jingdezhen/porcelain': ('Фарфоровая столица', 'Цзиндэчжэнь обжигает фарфор больше тысячи лет: как центр императорских печей он отправлял ко двору свои лучшие изделия. Каолин, главное сырьё фарфора, получил имя от здешней деревни Гаолин, и сегодня город по-прежнему притягивает художников-керамистов со всего мира.'),
  'jingdezhen/kiln': ('Древняя печь', 'В культурном комплексе «Древняя печь» сохраняются традиционные дровяные печи и ремесленные мастерские. От «драконьих печей», тянущихся по склону, до печей яйцевидной формы — здесь можно проследить испытание фарфора огнём, пока мастера у всех на глазах работают на гончарном круге и наносят глазурь.'),
  'jingdezhen/bluewhite': ('Сине-белый фарфор', '«Цинхуа» — кобальтово-синие узоры, нанесённые под глазурь на белоснежный фарфор, — всемирно известная подпись Цзиндэчжэня. Достигший зрелости в эпохи Юань и Мин, этот стиль разошёлся по миру по Шёлковому пути и морским маршрутам и стал страстью коллекционеров при европейских дворах.'),
  'jingdezhen/painting': ('Роспись по фарфору', 'В Цзиндэчжэне фарфор — не просто сосуд, а холст: тончайшими кистями мастера пишут на нём пейзажи, птиц и стихотворные строки. Такие техники, как подглазурная роспись и надглазурная эмаль, передаются из поколения в поколение, а подписные работы мастеров коллекционируют, как картины.'),
  'jian/jinggang': ('Горы Цзинганшань', 'Окутанные туманом горы Цзинганшань — место, где в 1927 году была основана первая сельская база китайской революции. Сегодня это сердце «красного туризма»: помимо исторических памятников горы встречают любителей природы водопадами, бамбуковыми лесами и морями облаков, перекатывающимися под вершинами.'),
  'jian/torch': ('Искра революции', 'Поговорка «из искры возгорится степной пожар» описывает, как революция распространилась из этих гор по всей стране. Мемориалы, музеи и сохранённые штабы района Цзинган документируют ту трудную борьбу, а идущие историческими тропами наслаждаются широкими горными панорамами.'),
  'jian/academy': ('Академия Байлучжоу', 'Академия Байлучжоу, основанная в эпоху Сун на острове посреди реки Ганьцзян, веками воспитывала учёных; здесь учился и национальный герой Вэнь Тяньсян. Тихие дворы, со всех сторон обнятые рекой, остаются изящным напоминанием о классической традиции китайского образования.'),
  'jian/pine': ('Сосны Цзинганшань', 'Сосны, укоренившиеся на крутых склонах гор Цзинганшань, стоят несгибаемо наперекор туману и ветру. Растущие, цепляясь за голые скалы, эти деревья стали символом стойкости и надежды, а их силуэты, встающие на рассвете из моря облаков, — зрелище, которое нелегко забыть.'),
  'nanping/wuyi': ('Горы Уи', 'Горы Уишань с багровыми скалами, зелёными ущельями и вьющимся между ними прозрачным ручьём внесены в список ЮНЕСКО и за природу, и за культуру. Древние наскальные надписи, террасные чайные сады и следы академий Чжу Си вплетают эти горы и в историю китайской мысли.'),
  'nanping/rocktea': ('Утёсный чай «Да Хун Пао»', 'Да Хун Пао, «Большой красный халат», — венец «скальных чаёв», улунов, растущих на богатых минералами почвах уишаньских утёсов. Листья с вековых материнских кустов на скале достигали легендарных цен, а глубокий обжаренный аромат этого чая пользуется в чайном мире особым почтением.'),
  'nanping/bambooraft': ('Сплав по реке Девяти Изгибов', 'Ручей Девяти излучин течёт среди красных скал гор Уишань, делая девять широких поворотов. Гости на бамбуковых плотах, которыми лодочники управляют шестами, проплывают мимо загадочных древних лодок-гробов, укрытых высоко в скалах, и любуются пейзажем, меняющимся за каждым изгибом.'),
  'nanping/scholar': ('Чжу Си', 'Чжу Си, великий мастер неоконфуцианства, провёл значительную часть жизни в окрестностях гор Уишань, основывая здесь академии и обучая учеников. Его новое прочтение конфуцианской мысли веками формировало систему образования Китая и всей Восточной Азии.'),
  'shenzhen/skyscraper': ('Небоскрёбы Шэньчжэня', 'Ещё сорок лет назад рыбацкая деревня, Шэньчжэнь превратился в лес небоскрёбов, став первой особой экономической зоной Китая. Его силуэт, увенчанный уходящей в облака башней Пинъань, воплощает темп эпохи реформ — местные говорят о «шэньчжэньской скорости», когда этажи вырастают за ночь.'),
  'shenzhen/chip': ('Город технологий', 'На электронном рынке Хуацянбэй чипы, платы и детали дронов перетекают с прилавка на прилавок; в этом городе выросли такие гиганты, как Tencent, Huawei и DJI. В «китайской Кремниевой долине» идеи становятся прототипами за считаные дни — Шэньчжэнь называют мировой столицей аппаратных стартапов.'),
  'shenzhen/miniature': ('«Окно в мир»', 'Тематический парк «Окно в мир» собирает миниатюры знаменитых сооружений планеты — от Эйфелевой башни до пирамид. За один вечер здесь можно прогуляться по всем континентам; собственная «Эйфелева башня» парка подсвечивается по ночам, передавая игривый и амбициозный дух Шэньчжэня.'),
  'shenzhen/mangrove': ('Залив Шэньчжэнь', 'Мангровые леса залива Шэньчжэнь, раскинувшиеся у подножия небоскрёбов, — важная остановка птиц на путях миграции. Цапли и кулики кормятся на илистых отмелях, а набережная прибрежного парка дарит горожанам редкий вид, где природа и мегаполис стоят бок о бок.'),
  'xian/terracotta': ('Терракотовая армия', 'Тысячи глиняных воинов, охраняющих гробницу императора Цинь Шихуана, были случайно найдены в 1974 году крестьянами, копавшими колодец. Лицо каждого воина неповторимо; выстроенная безмолвными рядами армия являет мощь императора, искавшего бессмертия, и её часто называют восьмым чудом света.'),
  'xian/citywall': ('Городская стена Сианя', 'Городская стена Сианя эпохи Мин — самая полно сохранившаяся в Китае: её мощное тело охватывает старый город непрерывным прямоугольником. Взять напрокат велосипед и проехать по стене — классическое сианьское развлечение; со сторожевых башен современный город и древняя столица умещаются в один кадр.'),
  'xian/drumtower': ('Колокольная башня', 'Колокольная башня династии Мин в самом центре города отмечает сердце древней столицы: когда-то её колокол возвещал часы дня. Вместе с соседней Барабанной башней и гастрономическими улочками Мусульманского квартала позади неё она образует самую оживлённую площадь сианьских ночей.'),
  'xian/roujiamo': ('Роуцзямо', 'Мясо, часами тушённое со специями и вложенное в хрустящую лепёшку, — вот почему жоуцзямо называют «китайским бургером». Этот древний кусочек уличной кухни Шэньси идеально подходит суете столицы Шёлкового пути: он помещается в одной руке и за два укуса связывает вас с тысячелетней традицией вкуса.'),
  'suzhou/garden': ('Классические сады Сучжоу', 'Классические сады Сучжоу — произведения мастерства, воссоздающие природу на малом пространстве с помощью каменных горок, прудов и павильонов; лучшие из них входят в список Всемирного наследия ЮНЕСКО. Каждое окно обрамлено, как картина, а прогулка по дорожкам похожа на разворачивание живописного свитка, меняющегося с каждым шагом.'),
  'suzhou/watertown': ('Город на воде', 'С его каналами, горбатыми каменными мостами и белёными домами Сучжоу называют «Венецией Востока». Вдоль старинных улочек вроде Пинцзянлу вода течёт прямо у порогов; скользя на лодке, слышишь звуки пипы и местных баллад, доносящиеся из чайных.'),
  'suzhou/embroidery': ('Сучжоуская вышивка', 'Сучжоуская вышивка — тысячелетнее ремесло, выполняемое по шёлку нитями тоньше волоса; величайшие мастера способны вышить разные узоры на двух сторонах одной ткани. Это искусство, передающее иглой блеск кошачьей шерсти или чешую рыбы, воплощает терпение и утончённость города.'),
  'suzhou/kunqu': ('Опера Куньцюй', 'Куньцюй, почитаемая как мать всей китайской оперы, родилась в окрестностях Сучжоу; её узнают по мелодиям, льющимся, как вода, и изысканно стилизованным жестам. Это искусство, внесённое в список нематериального наследия ЮНЕСКО, и сегодня исполняют в садовых павильонах и камерных театрах.'),
  'kunming/stoneforest': ('Каменный лес', 'Гигантские известняковые столбы, выточенные водой за миллионы лет, образуют близ Куньмина лабиринт, известный как Каменный лес. Местный народ сани рассказывает об этих скалах через легенду об Ашиме — прекрасной девушке, обращённой в камень, которая и поныне встречает гостей в облике одного из знаменитых столбов.'),
  'kunming/springcity': ('Город Вечной Весны', 'На высоком Юньнаньском плато зимы мягкие, а лета прохладные — поэтому Куньмин называют «городом вечной весны», где цветы никогда не вянут. Здесь работает один из крупнейших цветочных рынков Азии, а свежие букеты продают даже на уличных углах.'),
  'kunming/seagull': ('Черноголовые чайки', 'Каждую зиму тысячи озёрных чаек прилетают из Сибири, окрашивая берега озёр и городские парки Куньмина в белый цвет. Кормить их с руки — любимый зимний ритуал горожан, а возвращение чаек отмечают почти как приход нового времени года.'),
  'kunming/ricenoodle': ('Лапша «Переправа через мост»', 'Лапша «через мост» — фирменное блюдо Юньнани: на стол подают обжигающий бульон, а тонкую рисовую лапшу и добавки кладут в чашу прямо у вас на глазах. По легенде, жена, носившая обеды через мост занимавшемуся мужу, придумала этот способ сохранять суп горячим.'),
  'jinan/spring': ('Город источников', 'В Цзинане подземные воды пробиваются на поверхность в самом сердце города; любимец из 72 знаменитых источников — бурлящий источник Баоту. В «городе источников» чистая вода бежит даже по переулкам старых кварталов, и местные до сих пор гордятся тем, что заваривают чай родниковой водой.'),
  'jinan/daminglake': ('Озеро Даминху', 'Питаемое городскими источниками озеро Даминху — городской оазис в кольце ив и лотосов. Летом среди цветущих лотосовых зарослей скользят лодки, а прибрежные павильоны и чайные хранят тот неторопливый, изящный ритм жизни, которым Цзинань славится в китайской литературе.'),
  'jinan/buddhamountain': ('Гора Тысячи Будд', 'На склонах горы Тысячи Будд за века были высечены сотни изображений Будды; древнейшие рельефы восходят к династии Суй. Поднимаясь по тропам, посетители видят и статуи в каменных нишах, и, с вершины, широкую панораму Цзинаня — города источников.'),
  'jinan/poet': ('Поэтесса Ли Цинчжао', 'Ли Цинчжао, почитаемая как величайшая поэтесса Китая, родилась в этом городе источников в эпоху династии Сун. Её тонко-печальные стихи в жанре цы говорят о любви, изгнании и утрате; мемориальный зал у источника Баоту хранит тот мир с журчанием воды, что породил её строки.'),
  'ningbo/library': ('Павильон Тяньи', 'Основанный при династии Мин павильон Тяньигэ — старейшая сохранившаяся частная библиотека Азии, созданная сановником, беззаветно преданным книгам. Чтобы уберечь редкие рукописи от сырости и огня, её задумали почти как храм книги — с садом, прудом и строгими семейными правилами о том, кому дозволено войти.'),
  'ningbo/port': ('Порт Нинбо-Чжоушань', 'Порт Нинбо-Чжоушань — самый загруженный в мире по грузообороту: его берег превращён в лес контейнеровозов и исполинских кранов. Морская история города уходит в глубь веков — Нинбо был одними из ворот отправления древнего Морского шёлкового пути.'),
  'ningbo/tangyuan': ('Танъюань', 'Танъюань по-нинбоски — шелковистые шарики из клейкой рисовой муки со сладкой кунжутной пастой внутри: надкусишь — и тёплая начинка вытекает, как маленький сюрприз. Фирменное лакомство Праздника фонарей, своей круглой формой оно символизирует единство семьи и встречу после разлуки.'),
  'ningbo/seafood': ('Морепродукты', 'Обращённый к Восточно-Китайскому морю Нинбо накрывает стол дарами воды: жёлтый горбыль, крабы и моллюски составляют основу его кухни. Местный вкус ценит баланс «солёного и свежего» — простое приготовление на пару и лёгкая засолка, никогда не заглушающие собственный вкус рыбы, стали его фирменным почерком.'),
  'shijiazhuang/bridge': ('Мост Чжаочжоу', 'Построенный при династии Суй мастером Ли Чунем мост Чжаочжоу — древнейший в мире каменный арочный мост с открытыми пазухами. Изящная арка, около 1400 лет выдерживающая наводнения и землетрясения, вошла в учебники как классический шедевр китайской инженерии.'),
  'shijiazhuang/clifftemple': ('Гора Цанъянь', 'На горе Цанъянь храм, стоящий на каменном мосту, перекинутом между двумя утёсами, создаёт один из самых поразительных пейзажей Китая. К нему поднимаются по крутым каменным лестницам из зелёной долины; именно он стал декорацией финальной сцены фильма «Крадущийся тигр, затаившийся дракон».'),
  'shijiazhuang/redbase': ('Сибайпо', 'Деревня Сибайпо близ Шицзячжуана служила штабом революции на завершающем этапе гражданской войны; в её глинобитных двориках строились планы основания Нового Китая. Ныне это одна из священных остановок «красного туризма»: скромные деревенские дома — свидетели великих решений истории.'),
  'shijiazhuang/pharma': ('Фармацевтический город', 'Шицзячжуан — один из крупнейших фармацевтических центров Китая, известный как «город лекарств», прежде всего благодаря антибиотикам и фармацевтическому сырью. Молодая провинциальная столица, выросшая на железнодорожном узле, соединяет свою промышленную идентичность с фармацевтикой и современным производством.'),
  'taiyuan/jincitemple': ('Храм Цзиньцы', 'Храм Цзиньцы на окраине Тайюаня — самый изящный храмовый сад северного Китая со священными источниками, вековыми кипарисами и статуями служанок эпохи Сун. В деревянном Зале Святой Матери у каждой фигуры своё выражение лица — будто они перешёптываются уже тысячу лет.'),
  'taiyuan/coalcart': ('Угольный край', 'Горы Шаньси пронизаны угольными жилами, и немалая часть энергии Китая добывается именно здесь; Тайюань — столица этого богатства. Добыча угля дала городу промышленность, железные дороги и культуру тяжёлого машиностроения, а сегодня он старается уравновесить угольное наследие чистой энергетикой.'),
  'taiyuan/vinegar': ('Выдержанный уксус', 'Выдержанный «зрелый» уксус Шаньси получают долгим брожением гаоляна и злаков; его ценят за тёмный цвет и дымную кислинку. Местные поливают им всё — от лапши до пельменей; здесь уксус не приправа, а почти часть самосознания.'),
  'taiyuan/twinpagoda': ('Парные пагоды', 'Две восьмигранные пагоды династии Мин, возвышающиеся бок о бок на юго-востоке города, веками остаются неизменной эмблемой Тайюаня. Кирпичные башни демонстрируют тонкость каменной кладки, а весной цветущие вокруг них сливы дарят самый фотогеничный момент визита.'),
  'hohhot/lamatemple': ('Монастырь Дачжао', 'Основанный в эпоху Мин храм Дачжао — духовное сердце Хух-Хото, а его главное сокровище — статуя Будды из серебра. Этот центр тибетского буддизма в степи, окутанный дымом благовоний, молитвенными барабанами и тихими песнопениями, открывает мир, совершенно отдельный от городского шума.'),
  'hohhot/dairy': ('Молочная столица', 'Крупнейшие молочные бренды Китая родились в Хух-Хото, где степная молочная традиция выросла в современную индустрию, — город называют «молочной столицей». На столе монгольские лакомства — молочный чай, сушёный молочный творог и топлёные сливки — по-прежнему живут бок о бок с фабричными марками.'),
  'hohhot/wrestling': ('Монгольская борьба', 'Монгольская борьба бёх — звёздное состязание праздника Наадам: борцы выходят на площадку в расшитых жилетах, исполняя танец орла. Победителя награждают аплодисментами за грацию не меньше, чем за силу, — в степи борьба вместе с верховой ездой и стрельбой из лука входит в «три мужских искусства».'),
  'hohhot/prairie': ('Травянистая равнина', 'Сразу за Хух-Хото до самого горизонта расстилается монгольская степь: летние пастбища колышутся, как зелёное море, где пасутся табуны лошадей и овцы. Гостей, ночующих в юртах, встречают молочным чаем и пиршеством из баранины, а ночью небо наполняется звёздами, давно забытыми в городе.'),
  'sanya/resortbeach': ('Тропический пляж', 'Санья на южной оконечности острова Хайнань — тропическая курортная столица Китая; за пудрово-белый песок и бирюзовую воду залива Ялун её называют «китайскими Гавайями». На пальмовых берегах лето длится круглый год — это одно из немногих китайских побережий, где можно купаться даже зимой.'),
  'sanya/guanyin': ('Статуя Гуаньинь', 'Статуя Гуаньинь, поднимающаяся на 108 метров над морем у Наньшаня, — одна из самых высоких статуй богинь в мире. Три её лика обращены к суше, морю и открытой воде; дорога-дамба к стопам богини милосердия притягивает и паломников, и любопытных путешественников.'),
  'sanya/diving': ('Дайвинг', 'С тёплой, кристально чистой водой Санья — дайверский рай Китая: коралловые рифы вокруг острова Учжичжоу кишат разноцветными рыбами. Новички погружаются на мелкие рифы с инструкторами, а заглянуть в тропический сад под поверхностью можно даже с одной лишь маской и трубкой.'),
  'sanya/coconutdrink': ('Кокос', 'В Санье кокос — часть повседневной жизни: вдоль пляжей торговцы вскрывают свежий плод мачете и протягивают его с трубочкой. Прохладная кокосовая вода — самое естественное лекарство от тропической жары, молоко идёт в местные блюда из курицы и десерты, а скорлупа превращается в поделки.'),
  'yangzhou/slenderlake': ('Озеро Тонкое', 'Озеро Шоусиху, «Стройное Западное озеро», получило имя как изящный поклон знаменитому озеру Ханчжоу; длинный узкий водный путь украшен ивами, белыми арочными мостами и павильонами. Пейзаж, восхищавший императоров династии Цин в их южных поездках, и сегодня изящен, как картина тушью.'),
  'yangzhou/friedrice': ('Жареный рис по-янчжоуски', 'Жареный рис по-янчжоуски — золотистая классика с креветками, яйцом и зелёным луком, обжаренная так, что каждая рисинка отделяется от другой; его имя живёт в китайских ресторанах по всему миру. Секрет — в простоте: каждое зёрнышко покрыто яйцом, ингредиенты свежие и никогда не в избытке.'),
  'yangzhou/morningtea': ('Утренний чай по-янчжоуски', 'День в Янчжоу начинается с ритуала «утреннего чая»: к крепкому чаю подают паровые пирожки, выпечку из теста, нарезанного тончайшей соломкой, и пельмени с бульоном внутри. В старых чайных этот завтрак растягивается на часы — торопиться здесь почти неприлично.'),
  'yangzhou/gegarden': ('Сад Гэюань', 'Сад Гэюань, построенный богатым соляным торговцем, обязан своим именем форме бамбуковых листьев. Его самая знаменитая находка — каменные горки, воплощающие четыре времени года в разных камнях: за несколько шагов проходишь от весны до зимы через вершину классического садового искусства.'),
  'weihai/navalisland': ('Остров Люгун', 'Остров Люгундао близ Вэйхая был базой Бэйянского флота — современного военного флота династии Цин, потерпевшего здесь поражение в войне с японским флотом. Сегодня остров с его музеями и старыми укреплениями рассказывает горькую, но поучительную страницу морской истории Китая.'),
  'weihai/swan': ('Лебединое озеро', 'Каждую зиму сотни лебедей-кликунов прилетают из Сибири и селятся на прибрежной лагуне близ Вэйхая. Белые птицы, скользящие в утреннем тумане, притягивают фотографов и любителей природы, а жители деревень заботятся о лебедях и подкармливают их, как соседей.'),
  'weihai/seacucumber': ('Морской огурец', 'Трепанг, выращенный в холодных чистых водах Вэйхая, — один из самых ценных деликатесов китайского стола. Считающийся очень питательным, он подаётся по особым случаям и дарится как почётный подарок; прибрежные фермы по его разведению — важная опора городской экономики.'),
  'weihai/cape': ('Мыс Китая', 'Мыс Чэншаньтоу к востоку от Вэйхая — одна из самых восточных точек, где китайская земля встречается с морем: солнце приветствует страну сначала здесь. По легенде, Первый император Цинь Шихуан добрался до этих мест в поисках земли бессмертия за волнами; мыс называют также «краем неба».'),
  'handan/taichi': ('Тайцзицюань', 'Окружённый стенами городок Гуанфу близ Ханьданя — родина стилей Ян и У тайцзицюаня; здесь учился легендарный мастер Ян Лучань. По утрам ученики, отрабатывающие медленные, текучие формы под стенами и во двориках, хранят живое наследие этого «мягкого» боевого искусства.'),
  'handan/congtai': ('Терраса Цунтан', 'Терраса Цунтай уцелела со времён могущественного царства Чжао эпохи Сражающихся царств; высокая платформа, с которой цари наблюдали церемонии и военные смотры, стоит теперь в сердце парка. Поднявшись на неё, обозреваешь более чем двухтысячелетнюю историю Ханьданя как древней столицы.'),
  'handan/idiom': ('Город идиом', 'Ханьдань — «город идиом»: более 1500 китайских идиом восходят к событиям и преданиям этой земли. Самая знаменитая — «учиться ханьданьской походке», о том, кто подражает другим, пока не забывает собственный шаг; она навсегда вписала имя города в язык.'),
  'handan/ciporcelain': ('Фарфор Цычжоу', 'Керамику Цычжоу узнают по смелым чёрным узорам, свободно нанесённым кистью по белому ангобу: цветы, рыбы и стихотворные строки положены на сосуды с искренностью народного искусства. Живая со времён династии Сун, эта традиция — керамика повседневной жизни, противовес фарфору императорского двора.'),
  'daqing/oilpump': ('Нефтяное месторождение', 'Открытие Дацинского нефтяного месторождения избавило молодую Китайскую Народную Республику от зависимости от привозной нефти; город буквально вырос на своих скважинах. Станки-качалки и сегодня неспешно кланяются по всей равнине, а Дацин вошёл в историю как крупнейшее нефтяное месторождение Китая.'),
  'daqing/oilworker': ('Железный человек', 'Нефтяник Ван Цзиньси получил прозвище «Железный человек» за упорство, с которым открывал скважины в лютый мороз; рассказывают, что однажды он прыгнул в яму с раствором и перемешивал буровую смесь собственным телом. Музей его имени и «дух Железного человека» хранят легенду об основании Дацина.'),
  'daqing/reedlake': ('Тростниковые озёра', 'Среди нефтяных вышек прячется неожиданная дикая природа: обширные тростниковые озёра и болота Дацина дают приют журавлям, лебедям и перелётным водоплавающим птицам. Осенью, когда золотые тростники колышутся на ветру, промышленный город превращается в птичий заповедник.'),
  'daqing/hotspring': ('Горячий источник', 'Вокруг Дацина горячие минеральные воды, поднимающиеся из глубин земли, дарят целебное убежище в холодные северо-восточные зимы. Уезд Линьдянь прославился как курортный городок горячих источников, и отдых в его парящих бассейнах — мягкий ответ суровому климату нефтяного города.'),
  'zibo/bbq': ('Цзыбоское барбекю', 'Барбекю Цзыбо славится своим трио: маленькая угольная жаровня, тонкие шампуры и мягкие тонкие лепёшки. Ты сам дожариваешь свой шампур, а потом заворачиваешь его в лепёшку со свежим луком и соусом — дружеский ритуал, покоривший китайские соцсети и за одну ночь сделавший город сенсацией всей страны.'),
  'zibo/cuju': ('Древний футбол (Цзюйцзюй)', 'В цуцзюй, древнейшую в мире форму футбола, играли в Линьцзы, столице древнего царства Ци, — и ФИФА признаёт это место родиной игры. Игра, в которой кожаный мяч держали в воздухе ногами, прожила богатую жизнь — от дворцового развлечения до воинской тренировки.'),
  'zibo/ceramic': ('Цзыбоская керамика', 'Печи Цзыбо горят уже более тысячи лет, делая город одним из самых укоренённых центров керамики северного Китая. Традиция, простирающаяся от повседневной посуды до художественного фарфора, живёт в его музеях и мастерских, а керамические ярмарки собирают мастеров со всей страны.'),
  'zibo/glass': ('Цветное стекло (Люли)', 'Люли — изделия, формуемые вручную из цветного расплавленного стекла, — ремесло Цзыбо, играющее со светом; его историческим центром слывёт район Бошань. Мастера тянут и гнут раскалённое стекло щипцами, и рождающиеся бусины, птицы и вазы сияют на солнце, как витражи.'),
  'taian/mounttai': ('Гора Тайшань', 'Тайшань, глава Пяти священных гор, — самая святая вершина Китая: веками императоры совершали здесь жертвенные обряды, возвещая небу о своём правлении. В скалы этой горы, внесённой в список ЮНЕСКО, врезаны надписи поэтов и каллиграфов — каждый камень здесь страница истории.'),
  'taian/sunrise': ('Восход на вершине', 'Главная награда за восхождение на Тайшань — встретить на вершине солнце, встающее над морем облаков. Тысячи людей поднимаются всю ночь, чтобы дождаться рассвета на пике Нефритового императора; когда горизонт алеет, ликование, взлетающее над толпой, вмиг смывает всю усталость.'),
  'taian/stonesteps': ('Каменная лестница', 'Около 7000 каменных ступеней, ведущих к вершине, — физическое испытание, которое паломники шаг за шагом проходят веками. Самый крутой участок называется «Восемнадцать поворотов к небу», а носильщики, ежедневно поднимающие и спускающие по этим лестницам грузы, — тихие герои горы.'),
  'taian/daitemple': ('Храм Дай', 'Храм Даймяо у подножия горы — величественный комплекс, где императоры останавливались и готовились перед обрядами на Тайшане. Его главный зал дворцовой архитектуры знаменит огромной фреской о странствии бога горы Тайшань, а древние кипарисы во дворах — свидетели истории.'),
  'lianyungang/monkey': ('Гора Царя Обезьян', 'Здесь возвышается Хуагошань, Гора цветов и плодов — родина Царя обезьян Сунь Укуна из романа «Путешествие на Запад». В Пещеру водной завесы входят за водопадом, а настоящие макаки, снующие по скалам, стирают границу между легендой и пейзажем.'),
  'lianyungang/seaport': ('Морской порт', 'Ляньюньган — тихоокеанский конец железнодорожного моста, протянувшегося через всю Евразию: поезда, загруженные здесь, идут через Среднюю Азию в Европу. Порт, который называют восточными морскими воротами Шёлкового пути, ощущается современным продолжением древних торговых дорог.'),
  'lianyungang/mountain': ('Гора Юньтай', 'Крутые пики горы Юньтай хранят высшую точку провинции Цзянсу — поразительное исключение в краю, известном своими низкими равнинами. С лесистыми склонами, храмами и хребтами, глядящими на море, этот массив — окно города в природу.'),
  'lianyungang/crystal': ('Кристальная земля', 'Уезд Дунхай в округе Ляньюньгана принимает один из крупнейших в мире рынков горного хрусталя. Прозрачные кристаллы, добытые из его земли, идут на всё — от украшений до промышленного сырья, а прилавки городского рынка искрятся сверкающими камнями.'),
  'maanshan/libai': ('Поэт Ли Бо', 'Ли Бо, почитаемый как величайший поэт Китая, провёл последние годы в окрестностях этого приречного города; его могила находится в соседнем Данту. Мемориальный парк хранит следы мастера, превратившего вино, луну и свободу в стихи, а Мааньшань гордо называет себя «городом поэзии».'),
  'maanshan/steel': ('Стальной город', 'Металлургический комбинат Маган сделал Мааньшань одной из ключевых баз чёрной металлургии Китая: его домны десятилетиями дымят на берегу Янцзы. Город уравновешивает индустриальную идентичность поэтическим прошлым — с одной стороны расплавленная сталь, с другой строки Ли Бо.'),
  'maanshan/rivercliff': ('Утесы Цайшицзи', 'Утёс Цайшицзи, отвесно обрывающийся в Янцзы, открывает один из самых поэтичных видов на реку. По преданию, именно здесь Ли Бо упал в воду, потянувшись обнять отражение луны, и шагнул в бессмертие; павильоны и тропы на утёсе до сих пор шепчут эту историю.'),
  'maanshan/moonwine': ('Лунный свет и вино', 'Луну и вино — два великих образа поэзии Ли Бо — в Мааньшане чтят до сих пор: в его память город проводит поэтические фестивали. Поднять чашу на берегу реки, глядя на луну, — самый простой способ разделить чувство с поэтом, жившим тысячу лет назад.'),
  'longyan/tulou': ('Земляные дома Юндин', 'Гигантские круглые тулоу, рассыпанные по горам Юндина, — дома-крепости, возведённые народом хакка из земли и дерева и внесённые в список Всемирного наследия ЮНЕСКО. За толстыми глинобитными стенами бок о бок живут десятки семей; дым очагов, поднимающийся со двора, несёт запах векового общинного быта.'),
  'longyan/redmeeting': ('Гутяньское собрание', 'В 1929 году в этой горной деревне округа Лунъянь состоялось историческое Гутяньское совещание, определившее принципы и курс Красной армии. Белёный зал заседаний сохранён до наших дней, и деревня притягивает тех, кто идёт по следам одного из поворотных моментов истории революции.'),
  'longyan/hakka': ('Культура хакка', 'Народ хакка, чьё имя означает «семьи-гости», заслужил его, переселяясь с севера Китая на юг, спасаясь от войн. В горах Лунъяня они веками хранят свой особый язык, блюда вроде курицы, запечённой в соли, и крепкие семейные узы.'),
  'longyan/mountain': ('Гора Гуаньчжи', 'Гора Гуаньчжи известна красной скальной вершиной, напоминающей, как говорят, шапку древнего чиновника; эти багровые утёсы данься окружены прозрачными озёрами и крутыми ущельями. С лестницами, вырубленными в скале, и лодочными прогулками по озеру гора слывёт природной жемчужиной южной Фуцзяни.'),
  'sanming/danxia': ('Тайнинский Данься', 'Тайнин на северо-западе провинции Фуцзянь — геопарк ЮНЕСКО с алыми песчаниковыми скалами, узкими ущельями и пещерами. Вода вытачивала этот каменный лабиринт миллионы лет; сегодня по нему можно плыть на лодке, глядя, как зелёные потоки скользят между багряными стенами.'),
  'sanming/shaxian': ('Закуски уезда Ша', 'Скромная кухня уезда Ша превратилась во всекитайский феномен дешёвой и сытной еды. Вонтоны с тончайшим тестом, лапша с арахисовым соусом и томлёные на пару супы подаются с одинаковым радушием в закусочных Шасянь, которые встречаются почти на каждой улице Китая.'),
  'sanming/forest': ('Зеленая столица', 'Саньмин — один из самых лесистых городов Китая: его горы одеты зеленью от хребтов до долин. Когда-то центр лесозаготовок, город повернулся к экотуризму и гордо носит звание «зелёной столицы» с чистым воздухом и лесными тропами.'),
  'sanming/goldenlake': ('Золотое озеро', 'Золотое озеро, или Цзиньху, — широкое водохранилище, вьющееся среди красных скал Данься в Тайнине. Лодочные экскурсии проводят вас по узким водным каньонам мимо отвесных стен и встроенного в скалу храма Ганьлу — редкий пейзаж, где вода встречается с камнем.'),
  'ningde/mudflat': ('Приливные равнины Сяпу', 'Каждый день отлив у побережья Сяпу открывает бескрайние илистые отмели, мерцающие в переменчивом свете. Плантации водорослей, ряды бамбуковых шестов и рыбаки на мелководье превратили этот берег во всемирно известное место встречи фотографов.'),
  'ningde/whitetea': ('Белый чай Фудин', 'Фудин — родина китайского белого чая: серебристые пушистые почки лишь подвяливают и сушат, никогда не обжаривая. Местная поговорка «год — чай, три года — лекарство, семь лет — сокровище» рассказывает, как этот нежный лист становится ценнее с возрастом.'),
  'ningde/taimu': ('Гора Тайму', 'Гора Тайму поднимается над морем округлыми гранитными шпилями, узкими расщелинами и пещерными проходами. С древности её называют «волшебной страной над морем»: тропы вьются между валунами и выводят к площадкам, где туман встречается с океаном.'),
  'ningde/croaker': ('Желтый горбыль', 'Укрытые бухты залива Саньдуао сделали Ниндэ крупнейшим в Китае центром разведения большого жёлтого горбыля. Плавучие садковые фермы образуют на воде целые посёлки, а нежное белое мясо этой рыбы, приготовленное просто на пару, венчает столы Фуцзяни.'),
  'shaoguan/redcliff': ('Гора Данься', 'Гора Данься — красный песчаниковый массив, давший имя ландшафтам «данься» по всему миру и внесённый в список Всемирного наследия ЮНЕСКО. Башни и столбы, изваянные ветром и водой, на закате горят, как угли; их исследуют по извилистым тропам и в речных круизах.'),
  'shaoguan/chantemple': ('Храм Наньхуа', 'Храм Наньхуа близ Шаогуаня — место, где Хуэйнэн, Шестой патриарх чань-буддизма (дзен), проповедовал своё учение. С историей почти в пятнадцать веков он остаётся священным сердцем южной школы чань, где паломники и сегодня идут по следам наставника сквозь дым благовоний.'),
  'shaoguan/ancestor': ('Улица предков', 'Переулок Чжуцзи в Наньсюне был перевалочным пунктом, где семьи, переселявшиеся с севера в эпоху Сун, останавливались перед освоением юга. Миллионы жителей Гуандуна и сегодня возводят свои родословные к этому узкому каменному переулку и год за годом возвращаются сюда в поисках имён предков.'),
  'shaoguan/yaodance': ('Народ Яо', 'Народ яо, живущий в горных уездах Шаогуаня, славится ослепительно вышитыми нарядами и танцами с длинными барабанами. На праздниках урожая барабаны эхом разносятся по долинам, а узоры вышивки, словно бесписьменный язык, передают историю родов из поколения в поколение.'),
  'zhanjiang/oyster': ('Устрицы Чжаньцзяна', 'Устрицы, выращенные в тёплых и чистых южных водах Чжаньцзяна, вырастают крупными и молочно-нежными. По вечерам они шипят на углях с чесноком и маслом у уличных лотков — пахнущий морем ритуал, без которого немыслима ночная жизнь города.'),
  'zhanjiang/navy': ('Военно-морской порт', 'Благодаря глубокой и укрытой естественной гавани Чжаньцзян служит базой Южного флота военно-морских сил Китая. Портовый город, когда-то арендованный Францией под названием Гуанчжоувань, сегодня является стратегическими морскими воротами страны в Южно-Китайское море.'),
  'zhanjiang/mangrove': ('Мангровый лес', 'Мангровый лес вдоль побережья Чжаньцзяна образует крупнейший мангровый заповедник Китая. В этом солёном лесу, наполняющемся и пустеющем с приливами, живут цапли, илистые прыгуны и крабы, а переплетённые корни защищают берег от штормов и служат яслями для мальков.'),
  'zhanjiang/donghai': ('Остров Дунхай', 'Остров Дунхай у берегов Чжаньцзяна славится пляжем, непрерывно тянущимся на много километров. Устойчивый ветер привлекает сюда сёрферов, а ещё остров известен традиционным «танцем человеческого дракона», в котором десятки исполнителей, встав плечом к плечу, превращаются в единого дракона.'),
  'maoming/lychee': ('Столица личжи', 'Маомин — один из крупнейших в мире районов выращивания личи: в начале лета его холмы краснеют от плодов. В императорские времена личи с этих земель спешно доставляли ко двору как дань, а вековые деревья в садах плодоносят и по сей день.'),
  'maoming/refinery': ('Нефтехимическая база', 'Маомин вырос в промышленный город в 1950-е годы на переработке горючих сланцев, а сегодня здесь расположен один из крупнейших нефтехимических комплексов Южного Китая. Нефтеперерабатывающие и этиленовые заводы дают этому зелёному аграрному краю мощный экономический хребет.'),
  'maoming/ladyxian': ('Леди Сянь', 'Госпожа Сянь, мудрая правительница шестого века, мирно объединила народы дальнего юга. Сотни храмов вокруг Маомина посвящены ей, а ежегодные поминальные обряды свидетельствуют о почитании, которое длится уже почти полторы тысячи лет.'),
  'maoming/seaside': ('Побережье', 'Побережье Маомина, известное как «пляж номер один Китая», тянется километрами золотого песка. Вдоль берега высажен казуариновый лес — зелёная защита от ветра; семьи проводят здесь день купаясь, а завершают его в ресторанах морепродуктов.'),
  'zhaoqing/sevenstar': ('Семь Звездных Скал', 'Семь известняковых скал поднимаются над Звёздным озером, повторяя, как говорят, очертания ковша Большой Медведицы. В скалах скрыты пещеры с надписями многих столетий, а прогулка по дамбам вдоль озера объясняет, почему это место называют «Гуйлинем Гуандуна».'),
  'zhaoqing/inkstone': ('Тушечница Дуань', 'Из «четырёх драгоценностей рабочего кабинета» самая прославленная тушечница — дуаньский камень из Чжаоцина. Пурпурный камень, добываемый здесь со времён династии Тан, в руках резчика становится произведением искусства: хорошая дуаньская тушечница не даёт туши высыхать и бережёт кисть.'),
  'zhaoqing/dinghu': ('Гора Динху', 'Гора Динху стала первым природным заповедником Китая в 1956 году. С нетронутым субтропическим дождевым лесом, водопадами и храмом Цинъюнь она служит прохладным убежищем, которое горожане ласково называют природным «кислородным баром».'),
  'zhaoqing/songwall': ('Городская стена династии Сун', 'Городская стена Чжаоцина была возведена при династии Сун и сохранилась почти по всему периметру. В слоях кирпича читаются следы ремонтов династии за династией, и прогулка по крепостному валу — это круг почти по тысячелетней истории города.'),
  'huizhou/westlake': ('Западное озеро Хуэйчжоу', 'Западное озеро Хуэйчжоу — изящный классический пейзаж с обсаженными ивами дамбами, каменными мостами и островками. Великий поэт Су Дунпо, сосланный сюда, обессмертил озеро в стихах, и одна из дамб на берегу до сих пор носит его имя.'),
  'huizhou/luofu': ('Гора Лофу', 'Гора Лофу — одна из самых священных даосских гор Южного Китая, веками притягивавшая к своим вершинам отшельников и алхимиков. В её лесах, знаменитых целебными травами, скрыты храмы, родники и тропы, уходящие в облака.'),
  'huizhou/alchemy': ('Алхимия Гэ Хуна', 'Гэ Хун, алхимик и врач эпохи Цзинь, удалился на гору Лофу, чтобы готовить эликсиры и писать медицинские труды. Его заметка о сладкой полыни в древнем справочнике спустя столетия вдохновила открытие современного лекарства от малярии.'),
  'huizhou/xunliao': ('Бухта Сюньляо', 'Залив Сюньляо очаровывает мелкой бирюзовой водой и длинной лентой светлого песка — это один из любимых курортов побережья Гуандуна. В посёлках, когда-то бывших рыбацкими деревушками, подают свежие морепродукты, а спокойное море идеально подходит семьям с детьми.'),
  'meizhou/weilongwu': ('Столица хакка', 'Мэйчжоу считается духовной столицей народа хакка, рассеянного по всему миру. Подковообразные дома вэйлунъу прислоняются к холмам, собирая целые кланы под одной крышей, и их дворы до сих пор наполняются родовыми праздниками.'),
  'meizhou/saltchicken': ('Курица, запеченная в соли', 'Курица, запечённая в соли, — самая известная классика кухни хакка: целую птицу заворачивают в бумагу и зарывают в раскалённую крупную соль. Соль не сушит мясо, а, наоборот, запечатывает соки внутри — получается шелковисто-нежное блюдо с ароматом имбиря.'),
  'meizhou/football': ('Родина футбола', 'Мэйчжоу — одно из мест, где современный футбол раньше всего укоренился в Китае, за что город называют «колыбелью китайского футбола». Здесь родился легендарный бомбардир Ли Хуэйтан, и страсть к игре по-прежнему живёт — от деревенских полей до профессиональных клубов.'),
  'meizhou/plum': ('Цветок сливы', 'Имя Мэйчжоу происходит от иероглифа «слива», а город питает река Мэйцзян — Сливовая река. Цветущая в зимнюю стужу слива считается символом стойкого и трудолюбивого духа народа хакка и встречается как мотив по всему городу.'),
  'jiangmen/diaolou': ('Диаолоу Кайпина', 'Башни дяолоу, возвышающиеся среди рисовых полей Кайпина, построили в начале двадцатого века эмигранты, вернувшиеся из-за границы. Задуманные как крепости против разбойников и наводнений, они соединяют западные колонны с китайскими крышами и ныне входят в список Всемирного наследия ЮНЕСКО.'),
  'jiangmen/qiaoxiang': ('Родина зарубежных китайцев', 'Цзянмэнь и окружающий его район Уи — родовое гнездо миллионов китайцев, живущих за рубежом. Эта диаспора, раскинувшаяся от Америки до Юго-Восточной Азии, строила на родине школы, дороги и особняки, придав городу облик, в котором переплелись Восток и Запад.'),
  'jiangmen/chenpi': ('Сушеная кожура мандарина', 'Сушёная мандариновая кожура чэньпи из Синьхуэя вялится на солнце и выдерживается годами перед употреблением. Она придаёт глубокий аромат кантонским блюдам и ценится в традиционной медицине; хорошо выдержанная кожура почитается почти как марочное вино.'),
  'jiangmen/birds': ('Рай птиц', '«Птичий рай» в Синьхуэе — это один гигантский баньян, чьи ветви пустили корни и покрыли целый островок. Здесь ночуют тысячи цапель и водоплавающих птиц, а знаменитое эссе писателя Ба Цзиня заставило весь Китай полюбить этот зелёный остров.'),
  'yangjiang/knife': ('Столица ножей', 'Янцзян — китайская столица ножей и ножниц: львиная доля кухонных клинков страны выходит из его мастерских и фабрик. Многовековая кузнечная традиция соединилась здесь с современными технологиями стали, и местные марки добрались до кухонь всего мира.'),
  'yangjiang/shipwreck': ('Затонувший корабль «Наньхай № 1»', '«Наньхай № 1» — торговое судно эпохи Сун, затонувшее на Морском шёлковом пути и веками спавшее на морском дне. Корабль подняли целиком и поместили в музей со стеклянным бассейном на острове Хайлин; из его трюма извлекли десятки тысяч фарфоровых изделий и драгоценностей.'),
  'yangjiang/hailing': ('Остров Хайлин', 'Остров Хайлин с серповидной бухтой Дацзяо и мягкими пляжами — один из самых любимых морских курортов Гуандуна. Дни здесь проводят купаясь в прибое, вечера — за свежими морепродуктами из рыбацкой гавани, а ещё на острове находится музей затонувшего судна «Наньхай № 1».'),
  'yangjiang/kite': ('Город воздушных змеев', 'Янцзян вместе с северным Вэйфаном считается одной из двух столиц воздушных змеев Китая. Традиционные змеи на бамбуковом каркасе делают здесь вручную из поколения в поколение, и каждую осень на праздник двойной девятки небо наполняется разноцветными крыльями.'),
  'qingyuan/rafting': ('Рафтинг в Цинъюане', 'Цинъюань с его бурными потоками, сбегающими с гор, называют в Китае «родиной рафтинга». Летом тысячи гостей несутся по пенным трассам на плотах, а долины дарят прохладные леса и каменные купели вдали от городской жары.'),
  'qingyuan/chicken': ('Цинъюаньская курица', 'Местная курица Цинъюаня с крапчатым оперением, тонкой костью и глубоким вкусом — самая желанная птица кантонской кухни. Выращенная на свободном выгуле, она чаще всего подаётся просто отваренной, с соусом из имбиря и зелёного лука: сама простота — доказательство её качества.'),
  'qingyuan/hotspring': ('Горячие источники', 'Богатые минералами горячие воды, бьющие в горных долинах Цинъюаня, сделали город курортным сердцем Гуандуна. Над открытыми бассейнами поднимается пар под шелест бамбуковых рощ, и отдыхающие из Гуанчжоу приезжают сюда на выходные смыть усталость.'),
  'qingyuan/yaoterrace': ('Рисовые террасы Яо', 'В деревнях народа яо в Ляньнане рисовые террасы ступень за ступенью взбираются по горным склонам. Возведённые вручную за столетия, весной они превращаются в зеркала воды, а осенью — в золотые лестницы, и среди них по-прежнему живут древние деревни яо.'),
  'chaozhou/guangjibridge': ('Мост Гуанцзи', 'Мост Гуанцзи через реку Ханьцзян, заложенный при династии Сун, уникален своей центральной частью из связанных борт к борту лодок. Понтонная секция ежедневно размыкается, пропуская суда, — за это мост причисляют к четырём знаменитым древним переправам Китая.'),
  'chaozhou/woodcarving': ('Позолоченная резьба по дереву', 'Золочёная резьба по дереву Чаочжоу — легендарное ремесло, укладывающее сцену за сценой в одну-единственную панель. Каждая деталь, от рыбацких сетей до героев оперы, вырезана с ювелирной точностью, и покрытые сусальным золотом работы наполняют храмы и особняки мерцанием.'),
  'chaozhou/chaoxiu': ('Вышивка Чаочжоу', 'Вышивка Чаочжоу — самая пышная ветвь гуандунского рукоделия: золотые и серебряные нити кладутся поверх набивки, создавая выпуклый, почти скульптурный эффект. Драконы и фениксы будто готовы спрыгнуть с ткани, украшая свадебные наряды и оперные костюмы.'),
  'chaozhou/kaiyuan': ('Храм Кайюань', 'Основанный в 738 году, в эпоху Кайюань династии Тан, храм и поныне носит имя того царствования. Более тысячелетия в его дворах не прерывается служба: курятся огромные курильницы, а залы украшены лучшими образцами чаочжоуской резьбы по дереву.'),
  'jieyang/citygate': ('Ворота Цзиньсянь', 'Ворота Цзиньсянь, «Врата приветствия добродетельных», — изящный уцелевший символ старого Цзеяна. Их деревянная башня с ярусными карнизами смотрит на городской ров, а имя хранит пожелание города радушно встречать мудрых и достойных.'),
  'jieyang/jade': ('Нефтяная столица', 'Янмэй, городок под Цзеяном, — один из крупнейших в Китае центров резьбы по нефриту и торговли им. Сырой жадеит из Мьянмы здесь режут, вырезают и полируют, а в торговых рядах мастера читают зелень, скрытую в каждом камне, словно делая ставку в азартной игре.'),
  'jieyang/jieyanglou': ('Башня Цзеян', 'Башня Цзеян — современный монумент, возрождающий древнюю архитектуру с размашистыми традиционными карнизами и величавым силуэтом. Внутри проходят культурные выставки, а сама башня — гордость народа Чаошаня за свои корни, воплощённая в камне и дереве.'),
  'jieyang/beefbroth': ('Говяжий бульон Чаошань', 'Говяжий бульон и хого Чаошаня — кухня, посвящённая свежести: у каждого отруба своё название и свои считанные секунды в прозрачном кипящем бульоне. Подают его с соусом сача, и это мастерство в простоте — гордость всего края.'),
  'yunfu/marble': ('Мраморное королевство', 'Юньфу известен как столица камнеобработки Китая: мрамор и гранит режут и полируют здесь уже много поколений. Тысячи мастерских, выстроившихся вдоль шоссе, отправляют столешницы, скульптуру и облицовку по всему миру — камень кормит этот город.'),
  'yunfu/patriarch': ('Шестой патриарх', 'Хуэйнэн, Шестой патриарх чань-буддизма, родился в Синьсине под Юньфу и здесь же провёл свои последние дни. Возведённый в его честь храм Гоэнь — умиротворённый центр, притягивающий паломников: именно здесь началась его история — от мальчика-дровосека до просветлённого наставника.'),
  'yunfu/tianlu': ('Гора Тяньлу', 'Гора Тяньлу — зелёная корона Юньфу: её хребты уходят в облака, а склоны укутаны чайными садами. По утрам долины часто заливает облачное море, и путников, поднявшихся к рассвету, награждает вид вершин, встающих из тумана.'),
  'yunfu/xijiang': ('Западная река', 'Сицзян, Западная река, — главный рукав системы Жемчужной реки и одна из самых оживлённых водных артерий Южного Китая. Баржи идут мимо Юньфу днём и ночью, и река остаётся жизненной жилой, несущей камень и сельские грузы вниз к Гуанчжоу и дальше в мир.'),
  'liuzhou/luosifen': ('Улиточные рисовые лапши', 'Лосыфэнь, рисовая лапша с улитками из Лючжоу, славится бульоном на речных улитках и резким кисловатым духом маринованных побегов бамбука. Запах издалека вызывает споры, но одной пробы обычно хватает, чтобы влюбиться; в виде готовых наборов это местное блюдо покорило весь Китай и вышло за его пределы.'),
  'liuzhou/autocity': ('Автогород', 'Лючжоу — промышленное сердце Гуанси и одна из главных автомобильных баз Китая. Выпускаемые здесь маленькие доступные электромобили стали символом городских улиц: местные жители полюбили их за то, что они помещаются даже на самых тесных парковках.'),
  'liuzhou/karst': ('Карст реки Лю', 'Река Лю опоясывает город, словно пояс, а вокруг со всех сторон поднимаются известняковые пики. За эту большую излучину Лючжоу прозвали «городом-чайником», и посреди промышленного города речные парки и карстовые вершины дарят неожиданную природную красоту.'),
  'liuzhou/liuhou': ('Поэт Лю Цзунюань', 'Лю Цзунъюань, великий литератор эпохи Тан, служил правителем в месте своей ссылки — Лючжоу, где велел рыть колодцы и заботился о бедных. В парке Люхоу в центре города стоит посвящённый ему храм, и поэт навсегда неотделим от города своих последних лет.'),
  'wuzhou/gemstone': ('Столица драгоценных камней', 'Учжоу — мировая столица искусственных драгоценных камней: львиная доля синтетического фианита гранится и полируется в мастерских этого речного города. Умелые руки наносят грань за гранью на крошечные камни, которые отсюда разлетаются по ювелирным рынкам всего мира.'),
  'wuzhou/liubaotea': ('Чёрный чай Любао', 'Любао из Учжоу — тёмный ферментированный чай, который смягчается с годами выдержки. Когда-то его возили на речных судах шахтёрам Юго-Восточной Азии, веря, что во влажном климате он поддерживает равновесие тела; старые выдержанные корзины этого чая ныне разыскивают коллекционеры.'),
  'wuzhou/turtlejelly': ('Черепаховое желе', 'Учжоу считается родиной гуйлингао — чёрного желе, приготовляемого из целебных трав. Слегка горьковатое, оно подслащивается мёдом и подаётся охлаждённым — освежающая традиция, которая, как верят, выводит «внутренний жар» тела во влажное южное лето.'),
  'wuzhou/dragonmother': ('Храм Матери-Дракона', 'Храм Матери Драконов на берегу Сицзяна посвящён богине, почитаемой покровительницей речного народа. По легенде, она вырастила пятерых драконов как родных детей и оберегала людей от наводнений; в праздничные дни храм наполняется благовониями и лентами с пожеланиями.'),
  'beihai/silverbeach': ('Серебряный пляж', 'Серебряный пляж Бэйхая оправдывает своё имя: белоснежный песок, богатый кварцем, сияет на солнце серебром. Прославленный как «первый пляж Поднебесной», берег тянется на километры, а мелкое тёплое море даёт бескрайний простор для купания и прогулок.'),
  'beihai/pearl': ('Жемчужный город', 'Хэпу под Бэйхаем славится жемчугом со времён династии Хань: «южный жемчуг» был одной из самых ценных даней императорскому двору. Поговорка «жемчужины возвращаются в Хэпу» родилась на этих берегах, а жемчужные фермы и ювелирные рынки продолжают традицию и сегодня.'),
  'beihai/weizhou': ('Остров Вэйчжоу', 'Вэйчжоу у берегов Бэйхая известен как самый молодой вулканический остров Китая. Его берега окаймляют чёрные лавовые скалы, коралловые рифы и банановые рощи, а каменная католическая церковь, построенная миссионерами в девятнадцатом веке, — самый неожиданный сюрприз острова.'),
  'beihai/oldstreet': ('Старая улица', 'Старая улица Бэйхая застроена аркадными зданиями цилоу, выросшими, когда порт открылся для внешней торговли в конце девятнадцатого века. В арочных фасадах слышны отголоски Юго-Восточной Азии и Европы, а сегодня улица хранит своё прошлое среди лотков с устричным омлетом и следов старых консульств.'),
  'qinzhou/nixingpottery': ('Гончарные изделия Нисин', 'Керамика нисин из Циньчжоу, обжигаемая вовсе без глазури, сама собой обретает в печи бронзовые, алые и пурпурные оттенки. Это ремесло, использующее смесь глин с двух берегов реки, причисляют к четырём знаменитым гончарным традициям Китая.'),
  'qinzhou/dolphin': ('Белый дельфин', 'Залив Саньнян в Циньчжоу — одно из самых известных мест обитания редкого китайского белого дельфина. Эти грациозные млекопитающие с возрастом розовеют и выныривают рядом с экскурсионными лодками; местные жители с гордостью оберегают тех, кого называют «морской пандой».'),
  'qinzhou/oysterfarm': ('Устричные фермы Циньчжоу', 'Мелководное, богатое питательными веществами море Маовэй у Циньчжоу — один из главных питомников молоди устриц в Китае. Его воды покрыты рядами плавучих плотов, а крупный мясистый урожай делает город устричной столицей юга, где в дни фестиваля жаровни не гаснут никогда.'),
  'qinzhou/general': ('Генерал Фэн Цзыцай', 'Цинский генерал Фэн Цзыцай в преклонном возрасте вернулся в армию и одержал историческую победу над захватчиками у заставы Чжэньнань на вьетнамской границе. В его родном Циньчжоу бывшая усадьба сохранена как музей, а имя генерала живёт как символ защиты родины.'),
  'guigang/lotus': ('Город лотосов', 'Гуйган известен в Китае как «город лотосов»: летом окрестные пруды и поля укрываются розово-белыми цветами. Корень и семена лотоса — незаменимая часть местной кухни, а ежегодный фестиваль лотоса наполняет город праздником.'),
  'guigang/uprising': ('Цзиньтяньское восстание', 'В 1851 году в деревне Цзиньтянь уезда Гуйпин Хун Сюцюань поднял знамя Тайпинского восстания. Одно из величайших народных движений девятнадцатого века разлилось отсюда и потрясло полстраны; сегодня мемориальный комплекс в деревне рассказывает об этой бурной эпохе.'),
  'guigang/nanshan': ('Храм Наньшань', 'Храм Наньшань в Гуйгане — тысячелетняя святыня, устроенная в естественных пещерах известнякового холма. На стенах гротов читаются надписи и стихи, высеченные при разных династиях, а в прохладных каменных залах безмолвно восседают статуи Будды.'),
  'guigang/sugarcane': ('Сахарный тростник', 'Гуанси — крупнейший источник китайского сахара, и плодородная речная равнина Гуйгана занимает важное место в этом сладком урожае. К осени тростник вырастает выше человеческого роста, а в сезон уборки дороги заполняются грузовиками, везущими его на заводы.'),
  'yulin/medicine': ('Рынок лекарственных трав', 'Рынок лекарственных трав Юйлиня — один из крупнейших центров торговли традиционными снадобьями в Южном Китае. В его рядах смешиваются запахи сушёных корней, коры и цветов, а торговцы, наследники многовекового знания, помнят нрав каждой травы наизусть.'),
  'yulin/goldenpalace': ('Дворец Юньтянь', 'Дворец Юньтянь — монументальное культурное сооружение, переосмысляющее традиционную дворцовую архитектуру в колоссальном масштабе. На его этажах выставлены тонкая резьба, бронзовые статуи и мифологические сцены, а позолоченные башни — самая яркая черта городского силуэта.'),
  'yulin/lychee': ('Личи', 'Тёплые холмы и долины Юйлиня покрыты садами личи и лонгана. В начале лета ветви клонятся под гроздьями красных плодов, рыночные прилавки ломятся от душистого урожая, а семьи отмечают день сбора как настоящий праздник.'),
  'yulin/beef': ('Юйлиньская говядина', 'Фирменная закуска Юйлиня, нюба, готовится из тонко нарезанной говядины, которую медленно вялят и томят в пряном соусе. Тёмное, чуть сладковатое и насыщенно-ароматное мясо едят с рисом или за чаем, а рецепты передаются в семьях из поколения в поколение.'),
  'baise/redbase': ('Восстание в Босэ', 'В 1929 году Байсэское восстание под руководством молодого Дэн Сяопина создало революционную базу на берегах реки Юцзян. Поэтому город — важная остановка на маршрутах «красной памяти» Китая: мемориальный зал и здания старого штаба доносят ту эпоху до наших дней.'),
  'baise/sinkhole': ('Карстовые воронки Лэе', 'Гигантские карстовые провалы, или тянькэны, уезда Лэе образуют одно из самых плотных скоплений таких пропастей на Земле. На дне колодцев глубиной в сотни метров растут нетронутые леса, а подземные реки и пещерные системы делают эти места любимым краем геологов и спелеологов.'),
  'baise/mango': ('Столица манго', 'Жаркие солнечные долины Байсэ входят в число важнейших районов выращивания манго в Китае. В середине лета склоны гор золотятся, грузовики развозят сладкие плоды по всей стране, а манго стало для этих горных уездов и источником дохода, и предметом гордости.'),
  'baise/aluminum': ('Алюминиевый город', 'Горы Байсэ богаты бокситами — рудой, сделавшей город южной базой алюминиевой промышленности Китая. Рудники и плавильные заводы составляют хребет местной экономики, а «серебристый» металл, скрытый под красной землёй, даёт работу тысячам семей.'),
  'hechi/longevity': ('Бама — край долгожителей', 'Бама под Хэчи — всемирно известный «край долголетия», где поразительно велика доля жителей, перешагнувших столетний рубеж. Секретом считают чистый воздух, простую пищу и неторопливую жизнь, и тысячи людей ежегодно приезжают в эти долины в поисках здоровья.'),
  'hechi/folksong': ('Лю Саньцзе', 'Ичжоу в Хэчи чтят как родину Лю Саньцзе, легендарной народной певицы народа чжуан, и это край чжуанской народной песни. В сказаниях «фея песни» побеждает помещиков в импровизированных песенных состязаниях — традиция, которая и сегодня с азартом живёт на песенных ярмарках.'),
  'hechi/bronzedrum': ('Бронзовый барабан', 'Бронзовый барабан — одна из самых священных вещей южных народов, таких как чжуан и яо, а Хэчи считается сердцем живой культуры бронзовых барабанов. Украшенные рельефами барабаны звучат на праздниках, призывая, как верят, благословение и защиту, и многие деревни берегут свои вековые барабаны как семейные реликвии.'),
  'hechi/geopark': ('Геопарк Карст', 'Карстовый край Хэчи — природная лаборатория из провалов, огромных пещерных залов и подземных рек. Природные каменные мосты и пещерные «окна» вокруг Фэншаня — звёзды геопарка: там, где свет падает сквозь колодцы, внизу открываются потаённые миры.'),
  'laibin/sugarcity': ('Сахарная столица', 'Равнины Лайбиня насколько хватает глаз покрыты сахарным тростником, за что город называют «сахарной столицей Китая». С началом зимней жатвы задымляют заводские трубы: из тростника делают сахар, патоку и бумагу, а над посёлками плывёт сладкий запах.'),
  'laibin/yao': ('Народ Даяо', 'Горы Даяо в Цзиньсю под Лайбинем — дом пяти самостоятельных ветвей народа яо, у каждой из которых свои наряды, говор и обряды. На деревенских праздниках блестят серебряные украшения и вышитые головные уборы, и это многообразие делает Цзиньсю живым музеем культуры.'),
  'laibin/hongshui': ('Река Хуншуй', 'Хуншуй, названная по красному илу, который она несёт, — могучая река, прорезающая горы Гуанси. Плотины в её долинах посылают электричество по всему югу, а прибрежные деревни наслаждаются пейзажами, которые река вырезает между карстовыми пиками.'),
  'laibin/shengtang': ('Гора Шэньтан', 'Гора Шэнтан — высочайшая вершина хребта Даяо и одна из «крыш» Гуанси. Весной её склоны вспыхивают алыми рододендронами, а на вершине море облаков, восход и гонимый ветром туман вознаграждают тех, кто поднялся.'),
  'chongzuo/waterfall': ('Водопад Дэтянь', 'Водопад Дэтянь низвергается широкими ступенями через реку на китайско-вьетнамской границе и считается крупнейшим трансграничным водопадом Азии. Бамбуковые плоты подвозят вас к прохладной дымке водяной завесы, а окружающие карстовые пики превращают пейзаж в китайскую живопись.'),
  'chongzuo/langur': ('Белолицый лангур', 'Белоголовый лангур живёт только среди известняковых холмов Чунцзо и считается одним из редчайших приматов мира. Ночь он проводит в расщелинах утёсов, а днём скачет по отвесным скалам; благодаря заповедникам его численность понемногу восстанавливается.'),
  'chongzuo/rockart': ('Наскальные рисунки Хуашань', 'Красные фигуры, нанесённые на скалы реки Цзоцзян около двух тысяч лет назад народом лоюэ, изображают тысячи людей, танцующих в позе лягушки. Как их рисовали на столь недоступных обрывах, спорят до сих пор; эти наскальные росписи внесены в список Всемирного наследия ЮНЕСКО.'),
  'chongzuo/borderpass': ('Перевал Дружбы', 'Застава Дружбы — исторические пограничные ворота, связывающие Китай с Вьетнамом, и одна из знаменитых застав страны. Её арочная башня среди зелёных гор веками встречала армии, караваны и посольства, а сегодня остаётся оживлёнными воротами приграничной торговли.'),
  'beijing/great-wall': ('Великая Китайская стена', 'Самое длинное оборонительное сооружение в мире — более 20 000 километров, строившихся веками для защиты северных рубежей Китая. Ближайший к Пекину участок Бадалин с каменными ступенями и сторожевыми башнями на гребнях хребтов — самый посещаемый отрезок стены.'),
  'beijing/temple': ('Храм Неба', 'Священный храмовый комплекс, где императоры династий Мин и Цин ежегодно молились Небу о богатом урожае. Его трёхъярусная круглая синяя крыша, возведённая без единого гвоздя, — один из самых узнаваемых символов китайской архитектуры.'),
  'beijing/pagoda': ('Пагода Тяньнин', 'Кирпичная пагода высотой около 57 метров с тринадцатью ярусами, оставшаяся от династии Ляо. С резными рельефами и восьмигранным корпусом это одно из старейших сохранившихся сооружений Пекина — свидетель тысячелетней истории города.'),
  'beijing/opera': ('Пекинская опера', 'Традиционное китайское сценическое искусство с двухсотлетней историей, соединяющее пение, речь, боевые искусства и акробатику. Красочный грим актёров (ляньпу) раскрывает характер каждого персонажа: красный означает верность, белый — коварство.'),
  'zunyi/huiyi': ('Музей совещания в Цзуньи', 'В самые тёмные дни Великого похода, в 1935 году, лидеры Коммунистической партии собрались в этом сером каменном особняке, изменили курс революции и открыли Мао путь к руководству. Сегодня дом стал музеем и превратил Цзуньи в сердце китайской карты «красного туризма».'),
  'zunyi/moutai': ('Маотай', 'Маленький городок Маотай на берегу реки Чишуй — родина легендарного байцзю, который называют национальным напитком Китая. Этот крепкий напиток из сорго, выдержанный годами, стал непременным атрибутом государственных банкетов; даже воздух городка пропитан ароматом брожения.'),
  'zunyi/loushan': ('Перевал Лоушань', 'Крутой перевал Лоушань, рассекающий горы, стал ареной исторической победы Красной армии во время Великого похода. Мао увековечил его в знаменитом стихотворении, написанном здесь; сегодня путешественники поднимаются на туманные скалы и читают его строки, высеченные в камне.'),
  'zunyi/chishui': ('Водопад Чишуй', 'Водопады срываются с красных данься-скал Чишуя в долину бамбуковых лесов и гигантских древовидных папоротников, уцелевших со времён динозавров. Название означает «красная вода» — река после дождя действительно становится алой, а весь этот пейзаж входит в природное наследие ЮНЕСКО «Китайская Данься».'),
  'liupanshui/coolcity': ('Люпаньшуй', 'Расположенный на высоком плато, где лето остаётся освежающе прохладным, Люпаньшуй с гордостью носит титул «прохладной столицы Китая». Каждое лето сюда сбегают жители знойных Сычуани и Чунцина, а город превратил свой мягкий климат в фестивали и горный туризм.'),
  'liupanshui/coal': ('Угольная база Юго-Запада', 'Выросший на богатых угольных пластах Люпаньшуй долго служил энергетическим очагом юго-западного Китая. Город поднялся на шахтах и стали в годы великой индустриализации двадцатого века, а сегодня уравновешивает своё шахтёрское прошлое зелёной энергетикой и туризмом.'),
  'liupanshui/grassland': ('Луга Умэн', 'Бескрайние луга плато Умэн, соседствующие с облаками, усеяны табунами лошадей и рядами ветряков на горизонте. Прохладным летом крестьяне народов и и мяо пасут здесь свои стада, а горный туман порой опускается в одно мгновение, превращая всю картину в сказку.'),
  'liupanshui/kiwi': ('Киви с красной сердцевиной', 'Киви с красной сердцевиной прекрасно растёт на прохладных туманных нагорьях вокруг Люпаньшуя и стал сладким зелёным сокровищем города. Плод с рубиновой серединкой слаще обычного киви, и в пору урожая горные деревни доверху наполняются ящиками с фруктами.'),
  'anshun/huangguoshu': ('Хуангошу', 'Хуангошу, крупнейший водопад Китая, с грохотом обрушивается с высоты 77 метров и рассыпает радуги в облаках брызг. Тропа ведёт через пещеру Водной завесы позади потока, позволяя взглянуть на мир сквозь стену воды — здесь снимали сцены классического сериала «Путешествие на Запад».'),
  'anshun/dixi': ('Опера Диси', 'Диси, представление с резными деревянными масками воинов и звоном гонгов на деревенских площадях, называют «живым ископаемым китайской оперы». Этот обрядовый театр пришёл в Гуйчжоу вместе с солдатами минских гарнизонов и уже около шести веков с прежним жаром пересказывает древние военные эпосы.'),
  'anshun/batik': ('Батик', 'Женщины народов буи и мяо рисуют на ткани расплавленным воском птиц, цветы и завитки узоров, а затем погружают полотно в краситель индиго. Краска, проникающая в тонкие трещинки воска, делает каждое изделие единственным в своём роде — потому батик Аньшуня называют ремеслом, не знающим близнецов.'),
  'anshun/tunpu': ('Деревни Туньпу', 'В каменных гарнизонных деревнях, основанных минской армией около 600 лет назад, народ туньпу до сих пор носит старинную одежду нанкинского покроя и говорит на архаичном диалекте. Прогулка по улочкам с каменными стенами похожа на шаг в минский городок, застывший во времени.'),
  'bijie/azalea': ('Азалиевый пояс Байли', 'Каждую весну горные хребты Бицзе вспыхивают алым, розовым и лиловым цветением азалий, а «Стоверстовый азалиевый пояс» считается крупнейшим природным азалиевым лесом мира. На апрельских праздниках крестьяне народов и и мяо встречают весну песнями посреди моря цветов.'),
  'bijie/zhijin': ('Пещера Чжицзинь', 'Пещера Чжицзинь, где гигантские сталагмиты поднимаются, словно каменный лес, носит прозвище «подземный дворец» и входит в число самых впечатляющих пещер Китая. В залах размером с собор посетителей завораживают изящные известняковые образования вроде «Дерева серебряного дождя».'),
  'bijie/caohai': ('Озеро Цаохай', 'Цаохай, мелкое травянистое озеро на плато Вэйнин, каждую зиму становится прибежищем редких черношейных журавлей. Когда рассеивается утренний туман, над водой разносятся голоса тысяч птиц, а лодочники тихо катают гостей на шестах среди камышей.'),
  'bijie/potato': ('Картофельная столица', 'Картофель, растущий на прохладных солнечных нагорьях, делает Бицзе одной из великих картофельных житниц Китая, а вэйнинский картофель славится на всю страну. Запечённый на углях, обжаренный до хруста и приправленный острым перцем на уличных лотках, скромный клубень — король кухни плато.'),
  'qujing/rapeseed': ('Рапсовые поля Лопина', 'В конце зимы равнина Лопин тонет в золотом цветении рапса, а карстовые конусы поднимаются среди полей, словно острова в жёлтом море. Цветение притягивает пчеловодов, фотографов и любителей мёда со всех концов, и сам воздух становится сладким.'),
  'qujing/ham': ('Ветчина Сюаньвэй', 'Сюаньвэйский окорок, веками засаливаемый и вяленный на горном воздухе, — гордость юньнаньского стола. Розово-красная мякоть и глубокий аромат ставят его в ряд самых знаменитых окороков Китая; он придаёт вкус всему — от супов до праздничных лунных пряников.'),
  'qujing/jiulong': ('Водопады Цзюлун', 'Близ Лопина река «Девяти драконов» спускается лестницей каскадов, и у каждого водопада своя ширина и свой характер. В полноводье эта картина в обрамлении золотых рапсовых полей считается одной из красивейших цепочек водопадов Китая.'),
  'qujing/sandforest': ('Разноцветный песчаный лес', 'В Цветном песчаном лесу в Луляне колонны песка, изваянные ветром и дождём, сияют оттенками от золота и ржавчины до белого и лилового. Цвета меняются вместе со светом, и этот природный сад скульптур стал любимой сценой съёмочных групп и фотографов.'),
  'yuxi/fuxian': ('Озеро Фусянь', 'Фусянь, одно из глубочайших озёр Китая, лежит в юньнаньском плато, словно горное зеркало кристально чистой воды. Легенды рассказывают о древнем поселении под его гладью, а рыбаки прибрежных деревень до сих пор ловят знаменитую озёрную рыбку канлан.'),
  'yuxi/nieer': ('Композитор Не Эр', 'Не Эр, автор музыки государственного гимна Китая, происходил из юйсийской семьи, и город с гордостью считает его своим. Музыкальный парк, мемориал и фестивали его имени помогают Юйси передавать мелодии рано ушедшего композитора от поколения к поколению.'),
  'yuxi/chengjiang': ('Чэнцзянские окаменелости', 'Кембрийские окаменелости Чэнцзяна возрастом 530 миллионов лет образуют объект Всемирного наследия ЮНЕСКО, с поразительной детальностью показывающий зарю животной жизни. В камне отпечатались даже мягкие ткани, что делает этих существ одними из богатейших свидетелей «кембрийского взрыва».'),
  'yuxi/kiln': ('Печи Юйси', 'Древняя юйсийская печь эпохи Юань считается местом рождения юньнаньской бело-голубой керамики. Вдали от прославленного Цзиндэчжэня местные гончары выработали собственный стиль и вписали свои кобальтовые узоры в керамическую традицию юго-запада.'),
  'dali/threepagodas': ('Три пагоды', 'Три изящные пагоды, уже тысячу лет возвышающиеся у подножия хребта Цаншань, — символ древних царств Наньчжао и Дали. Устояв под ударами землетрясений, они образуют самый любимый открыточный вид Дали: позади снежные вершины, впереди отражающий пруд.'),
  'dali/erhai': ('Озеро Эрхай', 'Эрхай, названный так за форму, напоминающую ухо, — высокогорное озеро, протянувшееся между горами Цаншань и равниной Дали. Белостенные деревни народа бай украшают его берега, а велопрогулка вокруг озера и рыбацкие лодки на рассвете — классические радости Дали.'),
  'dali/cangshan': ('Горы Цаншань', 'Цаншань с девятнадцатью вершинами и восемнадцатью ручьями, сбегающими между ними, поднимается за Дали, словно зелёный занавес. Мрамор по-китайски буквально называется «далийским камнем»: узорчатая порода из этих жил веками украшала дворцы и храмы.'),
  'dali/wind': ('Ветер, цветы, снег и луна', 'Ветер Сягуаня, цветы Шангуаня, снег Цаншаня и луна над Эрхаем — четыре красоты Дали перечисляют, как строки одного стихотворения. Эти четыре символа вплетены даже в головные уборы женщин народа бай — изящная формула, которой город описывает собственную природу.'),
  'lijiang/oldtown': ('Старый город Лицзян', 'Сотканный из каналов, мощёных улочек и деревянных домов под черепицей, Старый город Лицзяна — живое сердце культуры наси. Этот город ЮНЕСКО, знаменитый тем, что построен без крепостных стен, когда-то принимал караваны Чайно-лошадиного пути, и журчание бегущей воды до сих пор сопровождает вас в каждом переулке.'),
  'lijiang/snowmountain': ('Снежная гора Нефритового дракона', 'Снежная гора Нефритового дракона с покрытой ледниками вершиной высотой 5596 метров сияет над Лицзяном, словно спящий дракон. Народ наси почитает гору священной; канатная дорога поднимает гостей к ледниковому парку, а долина Голубой луны у подножия чарует бирюзовыми озёрами.'),
  'lijiang/dongba': ('Письменность донба', 'Дунба, рисуночное письмо жрецов наси, считается последней живой пиктографической письменностью мира. Тысячи рукописей хранят обряды, посвящённые духам природы, и космологию наси; этот уникальный архив внесён в реестр ЮНЕСКО «Память мира».'),
  'lijiang/tigerleaping': ('Ущелье Прыгающего тигра', 'По легенде, тигр одним прыжком перемахнул самое узкое место реки Цзиньша — отсюда и имя ущелья. Пропасть, уходящая вглубь между снежными горами Нефритового дракона и Хаба, входит в число глубочайших каньонов планеты, а высокая тропа по её склону — мечта любого трекера.'),
  'lincang/dianhong': ('Черный чай Дяньхун', 'Дяньхун, красный чай с золотыми почками из Фэнцина, родился лишь в прошлом веке, но быстро прославил имя Юньнани на весь мир. Ценимый за медово-карамельный настой, он входит в число самых уважаемых чёрных чаёв Китая, а листья древних чайных деревьев придают ему особую глубину.'),
  'lincang/wadrum': ('Деревянный барабан народа ва', 'Народ ва почитает деревянный барабан священным: считается, что его голос соединяет небо и людей. В горных деревнях Цанъюаня танец с барабанами, во время которого женщины взмахивают в такт длинными волосами, в дни урожая и праздников наполняет громом целые долины.'),
  'lincang/teatrees': ('Древние чайные деревья', 'Туманные горы Линьцана укрывают дикие и древние чайные деревья, возраст которых измеряется веками и даже тысячелетиями, — здесь спрятаны леса, где родился чай. Во время весеннего сбора крестьяне взбираются на гигантские деревья по лестницам, и из этих старых листьев делают один из самых желанных пуэров в мире.'),
  'lincang/lancang': ('Река Ланьцанцзян', 'Ланьцан, верхнее течение Меконга, спускается с Тибета и прорезает глубокие долины Линьцана на пути к югу, в Юго-Восточную Азию. Плотины вдоль его русла дают краю свет, а по склонам над берегами ярусами поднимаются чайные сады и тропические плодовые рощи.'),
  'puer/tea': ('Чай пуэр', 'Прессованный чай пуэр, названный в честь этого горного города, — живое сокровище, которое с возрастом становится мягче и дороже. Спрессованные в лепёшки листья могут храниться десятилетиями; когда-то караваны мулов несли их через горы в Тибет и к императорскому двору.'),
  'puer/coffee': ('Кофейная столица Китая', 'Большая часть китайского кофе растёт в садах арабики на туманных склонах Пуэра, так что столица чая, как ни удивительно, теперь пахнет латте. Кофейные фермы устраивают дегустационные туры, а молодые бариста мечтают вывести местное зерно на мировую сцену.'),
  'puer/teahorse': ('Чайный путь', 'Древний Чайно-лошадиный путь, по которому караваны мулов везли чайные плитки в Тибет, а обратно приводили в Китай лошадей, начинался в Пуэре и взбирался к перевалам, укутанным облаками. Следы мощённых камнем караванных троп и старые перевалочные городки до сих пор хранят память об этой суровой торговле.'),
  'puer/peafowl': ('Зеленый павлин', 'Тропические леса вокруг Пуэра — одно из последних убежищ зелёного павлина, одной из редчайших птиц Китая. Здешние заповедники дают приют не только этой великолепной птице, но и диким слонам с гиббонами, и город гордится своими лесами не меньше, чем чаем.'),
  'baoshan/volcano': ('Вулканы Тэнчуна', 'Девяносто семь потухших вулканических конусов выстроились на равнине Тэнчуна, придавая пейзажу сходство с лунной поверхностью. Гости поднимаются к кромкам кратеров или парят над конусами на воздушном шаре, а чёрный лавовый камень вложен даже в стены городских домов.'),
  'baoshan/rehai': ('Горячее море', 'В долине «Горячего моря» в Тэнчуне дымятся гейзеры и кипят озёра; самое знаменитое из них — огромный «Большой кипящий котёл». Гости пробуют яйца, сваренные на пару горячих источников, а затем нежатся в минеральных ваннах, ища целебное тепло этой вулканической земли.'),
  'baoshan/heshun': ('Древний город Хэшунь', 'Хэшунь, каменный городок купцов, веками торговавших с Бирмой и дальними краями, увидел, как заработанные состояния возвращались домой изящными усадьбами и школами. В городке находится одна из старейших сельских библиотек Китая, а лотосовые пруды и каменные мосты дышат покоем.'),
  'baoshan/gaoligong': ('Горы Гаолигун', 'Горы Гаолигун, протянувшиеся вдоль границы с Мьянмой, — сокровищница жизни с долинами бабочек, тёплыми лесами и тысячами видов растений. Поднимаясь от тропических долин к заснеженным хребтам, они укрывают бесчисленных редких обитателей — от гиббонов до птиц, которых почти никто не видел.'),
  'deyang/sanxingdui': ('Руины Саньсиндуй', 'Гигантские бронзовые маски с выпученными глазами, извлечённые из жертвенных ям, открытых в 1986 году, вывели на свет загадочную цивилизацию Шу возрастом три тысячи лет. Саньсиндуй с его золотыми жезлами и священными бронзовыми деревьями считается одной из величайших сенсаций китайской археологии.'),
  'deyang/jiannanchun': ('Цзяньнаньчунь', 'Цзяньнаньчунь, который гонят в Мяньчжу, — легендарный байцзю, чьё имя упоминается среди напитков, подававшихся при танском дворе. Древние бродильные ямы, используемые без перерыва, и цветочный аромат ставят его в ряд самых уважаемых имён сычуаньской традиции крепких напитков.'),
  'deyang/nianhua': ('Новогодние лубки из Мяньчжу', 'Расписанные вручную новогодние лубки-няньхуа из Мяньчжу вешают на двери удачу: богов-хранителей, пухлых младенцев и символы изобилия. Это ремесло, одна из великих традиций китайского новогоднего лубка, превращает каждый оттиск в самостоятельное произведение благодаря живым завершающим мазкам мастеров.'),
  'deyang/turbine': ('Столица тяжелой промышленности', 'Немалая доля гигантских турбин, генераторов и оборудования электростанций страны куётся в огромных цехах Дэяна. Город, признанный столицей тяжёлого машиностроения, — одна из тихих стальных мышц, держащих энергетическую инфраструктуру Китая.'),
  'mianyang/libai': ('Родина Ли Бо', 'Ли Бо, бессмертный среди поэтов, провёл детство в горах Цзянъю — здесь впервые проросли его строки, посвящённые лунному свету и вину. Мемориал и музей его имени каждый год собирают любителей поэзии по следам легендарного танского мастера.'),
  'mianyang/sciencecity': ('Город науки и технологий', 'Мяньян, единственный город, носящий официальный китайский титул «Города науки и технологий», строит будущее исследовательскими институтами и электронными заводами. Родина телевизоров Changhong, это самое «умное», одетое в лабораторный халат лицо Сычуани.'),
  'mianyang/qiang': ('Каменные башни народа цян', 'В горных деревнях Бэйчуаня веками стоят каменные сторожевые башни народа цян — мастерски сложенные, они были символом и обороны, и достоинства. Храня культ белого камня и вышивку по шерсти, цянские деревни поддерживают жизнь древней горной культуры.'),
  'mianyang/mifen': ('Рисовая лапша по-мяньянски', 'Тонкая рисовая лапша, дымящаяся в курином, говяжьем или потроховом бульоне, будит Мяньян ранним утром. Нежные нити готовятся за считаные секунды, а толпа, склонившаяся над пиалами у прилавка, — самый верный утренний ритуал города.'),
  'nanchong/langzhong': ('Древний город Ланчжун', 'Ланчжун, один из лучше всего сохранившихся древних городов, построенных по канонам фэншуй, дремлет в объятиях излучины реки Цзялин. Как родина ханьского астронома Лося Хуна он почитается колыбелью традиций китайского Нового года, а его пахнущие уксусом улочки хранят облик эпох Мин и Цин.'),
  'nanchong/silk': ('Столица шелка', 'Более двух тысяч лет разведения шелковицы и ткачества принесли Наньчуну титул шёлковой столицы китайского запада. Город, когда-то снабжавший тканями Шёлковый путь, и сегодня живёт шелкомотальными фабриками и музеем шёлка, а его блестящие ткани по-прежнему расходятся по мировым рынкам.'),
  'nanchong/zhangfei': ('Говядина Чжан Фэя', 'Чжан Фэй, герой эпохи Троецарствия, долгие годы служил в Ланчжуне, где до сих пор стоит его храм. Названная в его честь пряная вяленая говядина — угольно-чёрная снаружи и розово-красная внутри — озорной намёк на знаменитый темноликий образ героя.'),
  'nanchong/zhude': ('Родина Чжу Дэ', 'Маршал Чжу Дэ, один из командиров-основателей Народно-освободительной армии, родился в бедном крестьянском доме в Илуне. Скромная усадьба и мемориальный зал стали местом паломничества по истории современного Китая — здесь посетители ощущают силу скромных начал.'),
  'yibin/wuliangye': ('Улянъе', 'Улянъе, который гонят из сорго, риса, клейкого риса, пшеницы и кукурузы, обязан именем этим «пяти злакам» и входит в число самых ценных марок байцзю в Китае. Влажный климат Ибиня и вековые бродильные ямы дарят напитку его фирменный многослойный аромат.'),
  'yibin/firstcity': ('Первый город на Янцзы', 'Там, где сливаются реки Миньцзян и Цзиньша, река получает имя Янцзы — поэтому Ибинь называют «первым городом на Янцзы». Мыс, где две воды встречаются разными цветами, ныне окружён прибрежным парком и служит самым гордым символом города.'),
  'yibin/bamboosea': ('Бамбуковое море Шунань', 'Бамбуковое море Шунань, укрывающее больше сотни холмов, колышется на ветру, словно безбрежный зелёный океан. Прохладные лесные тропы, скрытые водопады и кухня, построенная на бамбуковых побегах, обнимают путника, а съёмочные группы снова и снова возвращаются к этой зелени.'),
  'yibin/ranmian': ('Лапша «Жаньмянь»', '«Жаньмянь», замешанную почти без воды и щедро перемешанную с ароматным маслом, называют «горящей лапшой»: она настолько суха, что масло на ней можно поджечь. Приправленная острым перцем, сычуаньским перцем и жареным арахисом, она — пробуждающая звезда ибиньского завтрака.'),
  'luzhou/laojiao': ('Погреба Лаоцзяо', 'Глиняные бродильные ямы, непрерывно используемые с 1573 года, — сердце лучжоуской традиции байцзю «крепкого аромата». Живая микробная культура ям передаётся из поколения в поколение, а мастера-винокуры убеждены, что самые старые ямы дарят напитку самый глубокий букет.'),
  'luzhou/port': ('Порт на Янцзы', 'Основанный там, где река То впадает в Янцзы, Лучжоу — водные ворота Сычуани на пути к морю. Веками с его причалов грузили соль, вино и зерно, и сегодня контейнерный порт по-прежнему связывает внутренние провинции с нижней Янцзы и всем миром.'),
  'luzhou/longan': ('Сады лонгана', 'Лонган, медово-сладкий маленький плод, называемый «глазом дракона», растёт на тёплых склонах речных долин Лучжоу. Город владеет одними из самых северных крупных лонгановых садов Китая, и поздно созревающий плод осенью заваливает рыночные прилавки.'),
  'luzhou/umbrella': ('Масляные зонтики', 'Зонты из промасленной бумаги ручной работы мастеров Фэньшуя, с бамбуковыми спицами и расписанными вручную узорами, — изящное ремесло с четырёхвековой историей. Каждый зонт проходит через десятки операций и раскрывается навстречу удаче не меньше, чем дождю: его круглая форма — символ целостности и счастья.'),
  'leshan/giantbuddha': ('Лешаньский Будда', 'Высеченный в скале 71-метровый сидящий Будда уже двенадцать веков невозмутимо взирает на бурное слияние трёх рек. Колоссальный проект, начатый танским монахом Хайтуном ради защиты проплывающих лодок, ныне входит в наследие ЮНЕСКО — на одних только пальцах его ног могут стоять десятки людей.'),
  'leshan/emei': ('Гора Эмэйшань', 'Эмэй, одна из четырёх священных гор буддизма, зовёт паломников и путешественников своей Золотой вершиной, сияющей над морем облаков. Тропы вьются мимо древних монастырей, а в удачные дни на вершине можно увидеть кольцевую радугу, известную как «свет Будды».'),
  'leshan/monkeys': ('Макаки Эмэйшаня', 'Озорные макаки, живущие вдоль троп Эмэя, славятся тем, что нахально обшаривают сумки паломников. Местные зовут их хозяевами горы; развалившись на перилах и позируя для фото, обезьяны оставляют путникам самые весёлые — и самые хулиганские — воспоминания о подъёме.'),
  'leshan/qiaojiao': ('Говяжий суп «Цяоцзяо»', '«Цяоцзяо», говяжий суп, часами томящийся с целебными травами и специями, получил имя от посетителей, которые когда-то ели его, поставив ноги на высокие скамьи у прилавка. Уже около века эта дымящаяся пиала — классика улиц Лэшаня, превращающая в пиршество даже скромные потроха.'),
  'zigong/saltwell': ('Соляные скважины', 'Цзыгун около двух тысяч лет живёт соляными колодцами, и его гений бурения на бамбуковых канатах достиг вершины в колодце Шэньхай — первой скважине на земле, перешагнувшей тысячу метров. Деревянные буровые вышки и музей соли до сих пор рассказывают историю этой «соляной столицы».'),
  'zigong/lantern': ('Фестиваль фонарей в Цзыгуне', 'Каждый новогодний сезон Цзыгун превращается в сказочную страну колоссальных светящихся фонарных садов. Драконы, дворцы и герои легенд вырастают из шёлка и стали, а мастера фонарей из этого города теперь возводят такие праздники света по всему миру.'),
  'zigong/dinosaur': ('Музей динозавров', 'Тысячи окаменелостей, выступающих из юрских пластов Дашаньпу, делают Цзыгун динозавровой столицей Китая. В музее, построенном прямо над раскопом, костеносные слои показаны в том виде, в каком их нашли, а исполинские скелеты зауроподов уносят посетителей в глубину юрского периода.'),
  'zigong/rabbit': ('Холодный кролик', '«Лэнту», кролик, подаваемый холодным в остром масле с сычуаньским перцем и арахисом, — одна из самых дерзких закусок Сычуани, и её родина — Цзыгун. Рождённая за сытными столами солеваров, кухня города и сегодня хранит традицию щедрости на специи.'),
  'panzhihua/steel': ('Столица ванадия и титана', 'Паньчжихуа, встроенный в горную долину реки Цзиньша, — гигантский стальной город, разрабатывающий богатейшие в мире залежи ванадия и титана. Поднятый с нуля в годы великой индустриализации двадцатого века, он получил имя от огненно-красного цветка местного дерева капок.'),
  'panzhihua/fruitvalley': ('Солнечная фруктовая долина', 'Манго, гранаты и бананы сухой и жаркой долины Цзиньша дозревают в этом залитом солнцем микроклимате даже к зиме. Манго позднего урожая — гордость города, а фруктовые сады придают стальному городу неожиданно тропический вкус.'),
  'panzhihua/sunshine': ('Город зимнего солнца', 'С примерно 2700 часами солнца в год Паньчжихуа — оздоровительная остановка для тех, кто ищет мягкую и светлую зиму. Пенсионеры, спасаясь от северных холодов, приезжают сюда на весь сезон, а город венчает своё солнце спортивными лагерями и курортами с горячими источниками.'),
  'panzhihua/jinsha': ('Река Цзиньша', 'Цзиньша — «река золотого песка» — это верхнее течение Янцзы: прорезая глубокие долины, она бурно несётся через самое сердце Паньчжихуа. Гидроэлектростанции вдоль её русла питают весь край, а мосты и набережные наполняют её берега жизнью.'),
  'dazhou/gas': ('Столица природного газа', 'Под Дачжоу залегает Пугуан, одно из крупнейших месторождений природного газа в Китае, превращающее город в энергетическую базу страны. Отсюда трубопроводы тянутся к промышленным городам востока, и газовая экономика открыла новую эпоху для этого горного уголка Сычуани.'),
  'dazhou/ba': ('Наследие царства Ба', 'Здесь лежала земля древних воинов Ба, славившихся мечами в форме ивового листа; их бронза с тигровыми мотивами говорит с нами из руин Лоцзяба. Загадочная культура этого воинственного народа речных долин — один из древнейших пластов истории Сычуани.'),
  'dazhou/dengying': ('Говядина «Дэньин»', 'Говядина «дэнъин», нарезанная так тонко, что просвечивает у лампы, обязана именем театру теней, который когда-то устраивали при свете фонаря. Хрустящие ломтики бумажной толщины покрывают сладко-огненными специями; это изысканное лакомство Дачжоу украшает столы уже больше века.'),
  'dazhou/hanque': ('Каменные ворота эпохи Хань', 'Двухтысячелетние каменные башни «цюэ», стоящие среди полей Цюйсяня, — редкое дошедшее до нас изящество ханьской архитектуры. Когда-то венчавшие подходы к гробницам, эти резные надвратные башни впечатали в камень мир эпохи Хань — мифических зверей и сцены повседневной жизни.'),
  'guangyuan/jianmen': ('Застава Цзяньмэнь', 'Перевал Цзяньмэнь, где, как говорили, «один человек удержит десять тысяч», — замок древней дороги в Шу, а его скалы вздымаются, словно лезвия мечей. Узел армий со времён Троецарствия, перевал напоминает строку Ли Бо о том, что дорога в Шу «труднее, чем подъём на небо».'),
  'guangyuan/wuzetian': ('Родина императрицы У Цзэтянь', 'Считается, что У Цзэтянь, единственная женщина-император в истории Китая, родилась в Гуанъюане, и храм Хуанцзэ чтит её уже тысячу лет. Город ежегодно празднует память грозной правительницы женским фестивалем, а её статуя безмятежно восседает в храме на берегу реки.'),
  'guangyuan/plankroad': ('Древние дощатые дороги', 'Дощатые дороги, настланные на балки, вбитые в отвесные скалы, — памятники отваги, которые вообще сделали проходимой дорогу в Шу, «труднее подъёма на небо». Следы древних галерей сохранились в ущелье Минъюэ: гости идут по восстановленным настилам и чувствуют, как бьётся сердце старых караванов.'),
  'guangyuan/cypress': ('Кипарисовая аллея Цуйюнь', 'Десятки тысяч старых кипарисов выстроились вдоль древней дороги, превращая коридор Цуйюнь в зелёный туннель. Легенда приписывает часть посадок приказу Чжан Фэя, героя Троецарствия, а тенистый путь входит в число старейших сохранившихся придорожных аллей мира.'),
  'yaan/panda': ('Колыбель большой панды', 'Большая панда была впервые описана для науки в Баосине в 1869 году, когда доклад французского натуралиста Армана Давида познакомил мир с этим любимым всеми зверем. Панда-база в Бифэнся хранит это наследие, а туманные бамбуковые леса Яаня остаются колыбелью панды.'),
  'yaan/rain': ('Город дождей', '«Яаньский дождь» омывает крыши почти каждую ночь, и по утрам город сияет тысячей свежевымытых оттенков зелени. Местные перечисляют три прелести — яаньский дождь, яаньскую рыбу и яаньских красавиц; эта троица передаёт кроткий и щедрый дух дождевого города.'),
  'yaan/mengding': ('Чай с горы Мэндин', 'По преданию, около двух тысяч лет назад именно на горе Мэндин человек впервые посадил чай, за что гору считают колыбелью чайной культуры. Листья древних садов на вершине веками подносили императорам, а на туманных склонах и сегодня проводят чайные церемонии.'),
  'yaan/yayu': ('Рыба Я', 'Легендарная рыба Я из ручьёв, питаемых талыми снегами, подаётся в кипящих горшочках и считается одной из трёх прелестей города. В голове рыбы, знаменитой упругим белым мясом, спрятана крошечная косточка в форме меча, вокруг которой местные легенды сплели немало историй.'),
  'xianyang/qincapital': ('Имперская столица Цинь', 'Здесь стояла столица Цинь — династии, впервые объединившей Китай; из Сяньяна Цинь Шихуан шагнул по дороге к империи. Дворцы дошли до нас археологическими памятниками, где бронза и фундаменты шепчут о могуществе более чем двухтысячелетней давности.'),
  'xianyang/qianling': ('Мавзолей Цяньлин', 'Цяньлин, вырубленная в горе совместная гробница У Цзэтянь и её супруга императора Гао-цзуна, — одна из редких танских усыпальниц, дошедших до нас неразграбленными. Дорогу духов украшают каменные стражи и статуи иноземных послов, а знаменитая безнадписная стела У Цзэтянь оставляет суд над ней самой истории.'),
  'xianyang/zhengguo': ('Канал Чжэнго', 'Канал Чжэнго, прорытый на закате эпохи Сражающихся царств, оросил равнину Гуаньчжун, превратив её в житницу Цинь и заложив экономический фундамент объединения. Система, кормящая край уже более двух тысячелетий, остаётся гениальным образцом древней инженерии.'),
  'xianyang/guokui': ('Лепешка гокуй', '«Гокуй», хрустящая лепёшка размером и толщиной с крышку котла, числится среди знаменитых «десяти чудачеств» Шэньси. Медленно выпеченная на дровах, она хранится днями, а предание возводит её к древним походам, когда солдаты будто бы пекли её в собственных шлемах.'),
  'baoji/bronze': ('Столица бронзы', 'Из земли Баоцзи, сердца державы Чжоу, извлечены тысячи бронзовых сосудов с надписями — среди них хэ цзунь с древнейшим известным написанием имени «Китай» (Чжунго). Городской музей бронзы показывает это трёхтысячелетнее мастерство в одной из богатейших коллекций мира.'),
  'baoji/famen': ('Храм Фамэнь', 'Храм Фамэнь, хранитель реликвии — кости пальца Будды, служил священной сокровищницей танских императоров. Когда в 1987 году открыли тайную крипту под его пагодой, на свет явились ослепительные танские сокровища из золота, серебра и шёлка; сегодня реликвию принимает огромный храмовый комплекс.'),
  'baoji/taibai': ('Гора Тайбай', 'Тайбай, кровля хребта Циньлин высотой 3771 метр, питает легенды снегами, не тающими даже летом: «июньский снег на Тайбае» был одним из прославленных видов старого Гуаньчжуна. Тропы к его ледниковым озёрам идут по самой природной границе между севером и югом Китая.'),
  'baoji/saozi': ('Лапша саоцзы', 'Цишаньская лапша «саоцзы» с кисло-острым мясным соусом считается живым вкусом кухни эпохи Чжоу: её нити тонки, длинны и упруги. Уксус и жареный перец танцуют с морковью, яйцом и древесными грибами, а подавать гостям на свадьбах пиалу за пиалой — обычай многовековой давности.'),
};
